def _safe(s):
    return "".join(ch if ch.isalnum() or ch in "-_" else "_" for ch in str(s)).strip("_") or "x"


def _std(arr):
    a = np.asarray(arr, dtype=float)
    return float(np.std(a, ddof=1)) if a.size > 1 else 0.0


def _r2(x, y):
    x = np.asarray(x, float); y = np.asarray(y, float)
    if x.size < 3:
        return None
    try:
        m, b = np.polyfit(x, y, 1)
        yhat = m * x + b
        ss_res = float(np.sum((y - yhat) ** 2))
        ss_tot = float(np.sum((y - np.mean(y)) ** 2))
        return 1 - ss_res / ss_tot if ss_tot > 0 else None
    except Exception:
        return None


def infer_area(mean_rs):
    if mean_rs is None:
        return None
    if mean_rs < 100:
        return "dusuk dirençli / iletken filmler (metal, karbonize)"
    if mean_rs < 1e4:
        return "orta dirençli (yariiletken / karbon kompozit)"
    return "yuksek dirençli (yalitkana yakin polimer / film)"


def fmt_val(x):
    if x is None or (isinstance(x, float) and (np.isnan(x))):
        return "--"
    ax = abs(x)
    if ax != 0 and (ax < 1e-2 or ax >= 1e5):
        return "%.3e" % x
    return "%.4g" % x


_SI = [(1e9, "G"), (1e6, "M"), (1e3, "k"), (1.0, ""), (1e-3, "m"),
       (1e-6, "u"), (1e-9, "n"), (1e-12, "p"), (1e-15, "f")]


def eng(x, unit=""):
    """Muhendislik on ekiyle bicimler: 1500 -> '1.50 kohm'. unit='ohm','A','V','ohm/sq'."""
    if x is None or (isinstance(x, float) and np.isnan(x)):
        return "--"
    if x == 0:
        return "0 " + unit if unit else "0"
    ax = abs(x)
    for thr, pre in _SI:
        if ax >= thr:
            v = x / thr
            num = ("%.3g" % v)
            return ("%s %s%s" % (num, pre, unit)).strip()
    return ("%.3g %s" % (x, unit)).strip()


def eng_num(x):
    """Kart degeri icin: sayisal kisim + on ek (orn '1.50 k'); birim ayri etikette."""
    if x is None or (isinstance(x, float) and np.isnan(x)):
        return "--"
    if x == 0:
        return "0"
    ax = abs(x)
    for thr, pre in _SI:
        if ax >= thr:
            return ("%.3g %s" % (x / thr, pre)).strip()
    return "%.3g" % x


