#  VERITABANI  (tam veri + tercihler)
# ==============================================================================
class DataStore:
    def __init__(self):
        self.path = self._resolve_path()
        self.conn = sqlite3.connect(self.path, check_same_thread=False)
        self._init()

    @staticmethod
    def app_dir():
        """Calistirilabilirin/komut dosyasinin bulundugu klasor."""
        try:
            if getattr(sys, "frozen", False):
                return os.path.dirname(sys.executable)
            return os.path.dirname(os.path.abspath(__file__))
        except Exception:
            return os.getcwd()

    def _resolve_path(self):
        # Tasinabilir mod: exe/komut dosyasi yaninda b4pp.sqlite ya da PORTABLE
        # isaretci dosyasi varsa, veritabani orada tutulur (USB ile tasinabilir).
        try:
            d = self.app_dir()
            portable_db = os.path.join(d, "bss.sqlite")
            flag = os.path.join(d, "PORTABLE")
            if os.path.exists(portable_db) or os.path.exists(flag):
                self.portable = True
                return portable_db
        except Exception:
            pass
        self.portable = False
        try:
            base = os.path.join(os.path.expanduser("~"), ".bss")
            os.makedirs(base, exist_ok=True)
            return os.path.join(base, "bss.sqlite")
        except Exception:
            return ":memory:"

    def _ensure_col(self, table, col, decl):
        cols = [r[1] for r in self.conn.execute("PRAGMA table_info(%s)" % table)]
        if col not in cols:
            try:
                self.conn.execute("ALTER TABLE %s ADD COLUMN %s %s" % (table, col, decl))
            except Exception:
                pass

    def _init(self):
        c = self.conn
        c.execute("""CREATE TABLE IF NOT EXISTS users(
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            first TEXT, last TEXT, created_at TEXT, prefs TEXT,
            UNIQUE(first, last))""")
        c.execute("""CREATE TABLE IF NOT EXISTS measurements(
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER, sample TEXT, mode TEXT, n_repeats INTEGER,
            r_fit REAL, rs REAL, rho REAL, r_raw REAL, comp_hits INTEGER,
            created_at TEXT, data TEXT, note TEXT, tag TEXT)""")
        c.commit()
        self._ensure_col("users", "prefs", "TEXT")
        self._ensure_col("measurements", "comp_hits", "INTEGER")
        self._ensure_col("measurements", "data", "TEXT")
        self._ensure_col("measurements", "note", "TEXT")
        self._ensure_col("measurements", "tag", "TEXT")
        c.commit()

    def backup(self, dest):
        """Veritabanini tek dosya olarak dest'e kopyalar."""
        try:
            self.conn.commit()
            shutil.copyfile(self.path, dest)
            return True
        except Exception:
            return False

    def import_db(self, src):
        """src veritabanini mevcut konuma kopyalar ve yeniden baglanir."""
        try:
            # gecerli sqlite mi diye kabaca kontrol
            test = sqlite3.connect(src); test.execute("SELECT 1 FROM users LIMIT 1"); test.close()
        except Exception:
            return False
        try:
            self.conn.close()
        except Exception:
            pass
        try:
            shutil.copyfile(src, self.path)
        except Exception:
            pass
        self.conn = sqlite3.connect(self.path, check_same_thread=False)
        self._init()
        return True

    # ---- kullanici ----
    def get_or_create_user(self, first, last):
        c = self.conn
        c.execute("INSERT OR IGNORE INTO users(first,last,created_at) VALUES(?,?,?)",
                  (first, last, datetime.now().isoformat()))
        c.commit()
        row = c.execute("SELECT id FROM users WHERE first=? AND last=?",
                        (first, last)).fetchone()
        return row[0] if row else None

    def get_prefs(self, uid):
        try:
            row = self.conn.execute("SELECT prefs FROM users WHERE id=?", (uid,)).fetchone()
            if row and row[0]:
                return json.loads(row[0])
        except Exception:
            pass
        return {}

    def set_prefs(self, uid, prefs):
        try:
            self.conn.execute("UPDATE users SET prefs=? WHERE id=?",
                              (json.dumps(prefs), uid))
            self.conn.commit()
        except Exception:
            pass

    # ---- olcumler ----
    def add_measurement(self, uid, s):
        try:
            self.conn.execute(
                """INSERT INTO measurements
                   (user_id,sample,mode,n_repeats,r_fit,rs,rho,r_raw,comp_hits,created_at,data)
                   VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
                (uid, s.get("name"), s.get("mode"), s.get("n_repeats"),
                 s.get("R_fit"), s.get("Rs"), s.get("rho"), s.get("R_raw"),
                 s.get("comp_hits", 0), datetime.now().isoformat(),
                 json.dumps(s, default=float)))
            self.conn.commit()
        except Exception:
            pass

    def get_measurement(self, mid):
        try:
            row = self.conn.execute("SELECT data FROM measurements WHERE id=?",
                                    (mid,)).fetchone()
            if row and row[0]:
                return json.loads(row[0])
        except Exception:
            pass
        return None

    def list_measurements(self, uid, sample="", mode="hepsi", days=0,
                          all_users=False, limit=80):
        q = ("SELECT m.id, u.first||' '||u.last, m.sample, m.mode, m.r_fit, m.rs, "
             "m.rho, m.created_at, m.comp_hits, (m.data IS NOT NULL) "
             "FROM measurements m LEFT JOIN users u ON u.id=m.user_id WHERE 1=1")
        args = []
        if not all_users:
            q += " AND m.user_id=?"; args.append(uid)
        if sample:
            q += " AND m.sample LIKE ?"; args.append("%" + sample + "%")
        if mode and mode != "hepsi":
            q += " AND m.mode=?"; args.append(mode)
        if days and days > 0:
            cutoff = (datetime.now() - timedelta(days=days)).isoformat()
            q += " AND m.created_at>=?"; args.append(cutoff)
        q += " ORDER BY m.id DESC LIMIT ?"; args.append(limit)
        try:
            return self.conn.execute(q, args).fetchall()
        except Exception:
            return []

    def user_measurements(self, uid, limit=1000):
        try:
            return self.conn.execute(
                """SELECT sample,mode,r_fit,rs,rho,created_at,n_repeats,comp_hits
                   FROM measurements WHERE user_id=? ORDER BY id DESC LIMIT ?""",
                (uid, limit)).fetchall()
        except Exception:
            return []

    def user_stats(self, uid):
        rows = self.user_measurements(uid)
        st = {"count": len(rows), "modes": {}, "rs": [], "reps": [],
              "samples": {}, "last": rows[0] if rows else None,
              "first_date": None, "rows": rows}
        for sample, mode, r_fit, rs, rho, created, nrep, comp in rows:
            st["modes"][mode] = st["modes"].get(mode, 0) + 1
            if rs is not None:
                st["rs"].append(rs)
            if nrep:
                st["reps"].append(nrep)
            base = (sample or "").split("_")[-1]
            st["samples"][base] = st["samples"].get(base, 0) + 1
        if rows:
            st["first_date"] = rows[-1][5]
        st["mean_rs"] = float(np.mean(st["rs"])) if st["rs"] else None
        st["fav_mode"] = max(st["modes"], key=st["modes"].get) if st["modes"] else None
        st["area"] = infer_area(st["mean_rs"])
        return st


