        if has("profil", "oneri", "tavsiye"):
            return ("Profil sekmesi gecmis olcumlerini ozetler (R0, maks dR/R0 dagilimi) "
                    "ve sana ozel kisa oneriler verir.")
        if has("makul", "mantikli", "sence", "normal mi", "dogru mu", "olur mu", "anlamli"):
            return ("Kabaca: R0 numuneye gore birkac kohm - birkac Mohm arasi olabilir. "
                    "dR/R0 esnek sensorlerde onlarca hatta yuzlerce %% gorebilir; cok "
                    "kucukse (~%%1) temas zayif ya da numune gerilmemis olabilir. Gauge "
                    "factor birkac ile onlarca arasi tipiktir. Degerini yazarsan yorumlarim.")
        if has("kalibrasyon", "ariza", "servis", "iletisim", "mail", "eposta"):
            return ("Kalibrasyon/ariza icin: akgunes.batuhan@gmail.com. Yuk hucresi "
                    "kalibrasyonu icin bilinen agirlik as, sayim/N degerini Motor "
                    "sekmesindeki 'Yuk kalib.' alanina gir.")
