#  TANILAMA IS PARCACIGI  (open / short / 1 MΩ)
# ==============================================================================
class DiagWorker(threading.Thread):
    """Hizli dogrusal tarama yapip egim/direnc cikarir. step: 'open'|'short'|'ref'."""
    def __init__(self, smu, step, out_queue, nplc=1.0, settle=0.05):
        super().__init__(daemon=True)
        self.smu = smu; self.step = step; self.q = out_queue
        self.nplc = nplc; self.settle = settle

    def run(self):
        try:
            if getattr(self.smu, "simulate", False):
                import numpy as _np, time as _t
                _t.sleep(0.3)
                if self.step == "open":
                    self.q.put(("diag", {"step": "open", "R": 5e10, "aux": 3e-11})); return
                if self.step == "short":
                    self.q.put(("diag", {"step": "short", "R": 3.6, "aux": 0.0})); return
                self.q.put(("diag", {"step": "ref", "R": 1.0e6 * (1 + 0.01 * _np.random.randn()), "aux": 1e-6})); return
            self.smu.reset(); self.smu.set_phase("sample")
            if self.step == "short":
                # akim sur, gerilim olc -> egim = R (lead/kontak)
                self.smu.setup_isource(2.0, self.nplc)
                sweep = np.linspace(-1e-3, 1e-3, 7); xs, ys = [], []
                self.smu.output(True)
                for sv in sweep:
                    V, I, _ = self.smu.measure(sv); xs.append(I); ys.append(V)
                    time.sleep(self.settle)
                self.smu.output(False)
                R = float(np.polyfit(xs, ys, 1)[0]) if len(xs) >= 2 else float("nan")
                self.q.put(("diag", {"step": "short", "R": R,
                                     "aux": float(np.mean(ys))}))
            else:
                # open / ref: gerilim sur, akim olc -> egim = 1/R
                self.smu.setup_vsource(1e-3, self.nplc)
                sweep = np.linspace(-1.0, 1.0, 7); xs, ys = [], []
                self.smu.output(True)
                for sv in sweep:
                    V, I, _ = self.smu.measure(sv); xs.append(sv); ys.append(I)
                    time.sleep(self.settle)
                self.smu.output(False)
                g = float(np.polyfit(xs, ys, 1)[0]) if len(xs) >= 2 else 0.0
                R = (1.0 / g) if g != 0 else float("inf")
                imax = float(np.max(np.abs(ys))) if ys else float("nan")
                self.q.put(("diag", {"step": self.step, "R": abs(R), "aux": imax}))
        except Exception as e:
            try:
                self.smu.output(False)
            except Exception:
                pass
            self.q.put(("diag", {"step": self.step, "error": str(e)}))


