class ArduinoLink:
    def __init__(self):
        self.ser = None; self.q = queue.Queue(); self.alive = False; self.reader = None

    @staticmethod
    def ports():
        if not _list_ports:
            return []
        return [p.device for p in _list_ports.comports()]

    def open(self, port, baud=115200):
        if serial is None:
            raise RuntimeError("pyserial kurulu degil")
        self.ser = serial.Serial(port, baud, timeout=0.2)
        time.sleep(2.0)
        try:
            self.ser.reset_input_buffer()
        except Exception:
            pass
        self.alive = True
        self.reader = threading.Thread(target=self._loop, daemon=True); self.reader.start()

    def _loop(self):
        while self.alive and self.ser:
            try:
                line = self.ser.readline().decode("ascii", "ignore").strip()
            except Exception:
                break
            if not line:
                continue
            if line.startswith("T "):
                p = line.split()
                if len(p) >= 6:
                    try:
                        self.q.put(("T", {"pos": float(p[1]), "force": float(p[2]),
                                          "min": int(p[3]), "max": int(p[4]), "moving": int(p[5])}))
                    except Exception:
                        pass
            else:
                self.q.put(("msg", line))

    def send(self, cmd):
        if self.ser:
            try:
                self.ser.write((cmd + chr(10)).encode("ascii"))
            except Exception:
                pass

    def close(self):
        self.alive = False
        try:
            if self.ser:
                self.send("STREAM0"); self.send("EN0"); time.sleep(0.05); self.ser.close()
        except Exception:
            pass
        self.ser = None


class ArduinoSim:
    # Demo modunda Arduino yokken sanki varmis gibi davranir (ogrenme amacli).
    def __init__(self):
        self.q = queue.Queue(); self.alive = False; self.reader = None
        self.cmds = queue.Queue()
        self.pos = 0.0; self.target = 0.0; self.dir = 0; self.moving = False
        self.spmm = 1600.0; self.rate = 30.0; self.scale = 1000.0
        self.tare = 0.0; self.streaming = False; self.maxpos = 50.0; self.slack = 0.5
        self.cycling = False; self.cyc_amp = 0.0; self.cyc_base = 0.0
        self.cyc_total = 0; self.cyc_done = 0; self.cyc_phase = 0; self.cyc_dwell = 0.0; self.cyc_until = 0.0

    @staticmethod
    def ports():
        return ["DEMO (simulasyon)"]

    def open(self, port="DEMO", baud=0):
        self.alive = True
        self.q.put(("msg", "OK BSSRIG v1 (DEMO)"))
        self.reader = threading.Thread(target=self._loop, daemon=True); self.reader.start()

    def send(self, cmd):
        self.cmds.put(cmd)

    def close(self):
        self.alive = False

    def _raw(self):
        x = max(0.0, self.pos - self.slack)
        return 0.09 * x + 0.0025 * x * x + 0.01 * np.random.randn()

    def _force(self):
        return self._raw() - self.tare

    def _handle(self, c):
        c = c.strip()
        if c == "STREAM1": self.streaming = True; return
        if c == "STREAM0": self.streaming = False; return
        if c == "STOP": self.moving = False; self.cycling = False; return
        if c == "POS0": self.pos = 0.0; return
        if c == "TARE": self.tare = self._raw(); self.q.put(("msg", "OK TARE")); return
        if c == "HOME": self.target = 0.0; self.dir = -1; self.moving = True; return
        if c in ("EN1", "EN0", "PING"): self.q.put(("msg", "OK " + c)); return
        if c.startswith("CYCLE"):
            parts = c.split()[1:]
            try:
                amp = float(parts[0]); ncyc = int(float(parts[1])); dwell = float(parts[2]) if len(parts) > 2 else 0.0
            except Exception:
                amp, ncyc, dwell = 8.0, 5, 0.0
            self.cyc_base = self.pos
            if self.cyc_base + amp > self.maxpos: amp = max(0.0, self.maxpos - self.cyc_base)
            self.cyc_amp = amp; self.cyc_total = max(1, ncyc); self.cyc_dwell = dwell / 1000.0
            self.cyc_done = 0; self.cycling = True; self.cyc_phase = 0
            self.target = self.cyc_base + amp; self.dir = 1; self.moving = True
            self.q.put(("msg", "OK CYCLE")); return
        if " " in c:
            k, v = c.split(None, 1)
            try: v = float(v)
            except Exception: return
            if k == "SPMM": self.spmm = v
            elif k == "RATE": self.rate = v
            elif k == "SCALE": self.scale = v or 1.0
            elif k == "SETMAX": self.maxpos = max(0.1, v)
            elif k in ("MOVE", "JOG"): self.target = self.pos + v; self.dir = 1 if v > 0 else -1; self.moving = True
            elif k == "GOTO": self.target = v; self.dir = 1 if v > self.pos else -1; self.moving = True

    def _cyc_advance(self):
        if self.cyc_phase == 0:
            if self.cyc_dwell > 0: self.cyc_phase = 1; self.cyc_until = time.time() + self.cyc_dwell
            else: self.cyc_phase = 2; self.target = self.cyc_base; self.dir = -1; self.moving = True
        elif self.cyc_phase == 2:
            self.cyc_done += 1
            self.q.put(("msg", "CYC %d/%d" % (self.cyc_done, self.cyc_total)))
            if self.cyc_done >= self.cyc_total:
                self.cycling = False; self.q.put(("msg", "CYCLEDONE"))
            elif self.cyc_dwell > 0:
                self.cyc_phase = 3; self.cyc_until = time.time() + self.cyc_dwell
            else:
                self.cyc_phase = 0; self.target = self.cyc_base + self.cyc_amp; self.dir = 1; self.moving = True

    def _loop(self):
        dt = 0.05
        while self.alive:
            try:
                while True: self._handle(self.cmds.get_nowait())
            except queue.Empty:
                pass
            if self.moving:
                step = self.rate / 60.0 * dt
                reached = False
                if self.dir > 0:
                    self.pos = min(self.target, self.pos + step)
                    if self.pos >= self.maxpos: self.pos = self.maxpos; self.moving = False; self.cycling = False; self.q.put(("msg", "LIM MAX"))
                    elif self.pos >= self.target: reached = True
                else:
                    self.pos = max(self.target, self.pos - step)
                    if self.pos <= 0.0 and not self.cycling: self.pos = 0.0; self.moving = False; self.q.put(("msg", "LIM MIN"))
                    elif self.pos <= self.target: reached = True
                if reached:
                    self.moving = False
                    if self.cycling: self._cyc_advance()
                    else: self.q.put(("msg", "DONE"))
            elif self.cycling and self.cyc_phase in (1, 3) and time.time() >= self.cyc_until:
                if self.cyc_phase == 1: self.cyc_phase = 2; self.target = self.cyc_base; self.dir = -1; self.moving = True
                else: self.cyc_phase = 0; self.target = self.cyc_base + self.cyc_amp; self.dir = 1; self.moving = True
            if self.streaming:
                mn = 1 if self.pos <= 0.0 else 0
                mx = 1 if self.pos >= self.maxpos else 0
                self.q.put(("T", {"pos": round(self.pos, 3), "force": round(self._force(), 3),
                                  "min": mn, "max": mx, "moving": 1 if self.moving else 0}))
            time.sleep(dt)


