    # ===================================================== ANA
    def _play_intro(self):
        import tkinter as tk
        self._intro = ctk.CTkFrame(self, fg_color="#1b1730")
        self._intro.pack(fill="both", expand=True)
        self._intro_cv = tk.Canvas(self._intro, bg="#1b1730", highlightthickness=0)
        self._intro_cv.pack(fill="both", expand=True)
        self._intro_t0 = time.time()
        self._intro_cv.bind('<Double-Button-1>', lambda e: self._intro_skip())
        self.update_idletasks()
        self._intro_anim()

    def _intro_skip(self):
        try:
            self._intro.destroy()
        except Exception:
            pass
        self._intro_cv = None
        if not getattr(self, '_main_built', False):
            self._main_built = True; self._build_main()

    def _intro_anim(self):
        import math
        cv = getattr(self, "_intro_cv", None)
        if cv is None:
            return
        try:
            cv.delete("all")
        except Exception:
            self._build_main(); return
        W = cv.winfo_width() or self.winfo_width() or 1300
        H = cv.winfo_height() or self.winfo_height() or 820
        t = time.time() - self._intro_t0
        DUR = 30.0
        cx, cy = W / 2.0, H / 2.0
        ph = math.sin(t * 2.3) * 0.5 + 0.5          # 0..1 germe orani

        # ---- baslik ----
        cv.create_text(cx, cy - 168, text="B STRAIN SENSOR", fill="#ffffff",
                       font=("Consolas", 32, "bold"))
        cv.create_text(cx, cy - 130, text="Dongusel cekme-gevsetme olcum sistemi",
                       fill="#9b93b8", font=("Consolas", 13))

        # ---- numune + elektrotlar (yatay gerilir) ----
        span = (W * 0.30)
        halfw = span * (1.0 + 0.22 * ph)
        x1, x2 = cx - halfw, cx + halfw
        midY = cy - 6
        th = 30 * (1.0 - 0.28 * ph)
        # elektrot/kiskaclar
        cv.create_rectangle(x1 - 30, midY - 40, x1, midY + 40, fill="#8b5cf6", outline="")
        cv.create_rectangle(x2, midY - 40, x2 + 30, midY + 40, fill="#8b5cf6", outline="")
        # numune govdesi
        cv.create_rectangle(x1, midY - th / 2, x2, midY + th / 2, fill="#c4b5fd", outline="#7c3aed", width=2)
        # MWCNT benekleri
        for i in range(46):
            rx = x1 + (x2 - x1) * (((i * 41) % 100) / 100.0)
            ry = midY + ((((i * 57) % 100) / 100.0) - 0.5) * th
            cv.create_oval(rx - 1.3, ry - 1.3, rx + 1.3, ry + 1.3, fill="#5b21b6", outline="")
        # cekme oklari
        ar = 16 + 10 * ph
        cv.create_line(x1 - 44 - ar, midY, x1 - 44, midY, fill="#d9ccff", width=3, arrow="first")
        cv.create_line(x2 + 44, midY, x2 + 44 + ar, midY, fill="#d9ccff", width=3, arrow="last")

        # ---- dR/R0 dalga grafigi ----
        gx0, gx1 = W * 0.17, W * 0.83
        gy = cy + 120; gh = 76
        cv.create_line(gx0, gy, gx1, gy, fill="#3a325a")
        cv.create_text(gx0 - 6, gy - gh - 10, anchor="w", text="dR/R0",
                       fill="#c4b5fd", font=("Consolas", 12, "bold"))
        pts = []
        N = 150
        for i in range(N):
            xx = gx0 + (gx1 - gx0) * i / (N - 1)
            tt = t - (N - 1 - i) * 0.018
            val = math.sin(tt * 2.3) * 0.5 + 0.5
            yy = gy - val * gh
            pts += [xx, yy]
        if len(pts) >= 4:
            cv.create_line(*pts, fill="#8b5cf6", width=3, smooth=True)
        # kosan nokta
        cv.create_oval(gx1 - 4, (gy - gh * ph) - 4, gx1 + 4, (gy - gh * ph) + 4,
                       fill="#ffffff", outline="")

        # ---- yukleme cubugu ----
        prog = min(1.0, t / DUR)
        bx0, bx1 = W * 0.30, W * 0.70
        by = H * 0.82
        cv.create_rectangle(bx0, by, bx1, by + 8, outline="#3a325a")
        cv.create_rectangle(bx0, by, bx0 + (bx1 - bx0) * prog, by + 8, fill="#8b5cf6", outline="")
        cv.create_text(cx, by + 26, text="Yukleniyor...", fill="#9b93b8", font=("Consolas", 11))

        # ---- imza (sag alt, artistik) ----
        cv.create_text(W - 38, H - 48, anchor="se", text="by Batuhan",
                       fill="#ece3ff", font=("Segoe Script", 38, "bold italic"))
        sw = []
        for i in range(64):
            u = i / 63.0
            xx = (W - 270) + u * 232
            yy = (H - 30) + 11 * math.sin(u * math.pi) - 5 * math.sin(u * 3.2)
            sw += [xx, yy]
        cv.create_line(*sw, fill="#8b5cf6", width=3, smooth=True, capstyle="round")
        cv.create_line(W - 40, H - 30, W - 20, H - 42, W - 30, H - 22,
                       fill="#8b5cf6", width=3, smooth=True, capstyle="round")
        cv.create_oval(W - 270 - 3, H - 30 - 3, W - 270 + 3, H - 30 + 3, fill="#c4b5fd", outline="")

        if t < DUR:
            self.after(33, self._intro_anim)
        else:
            try:
                self._intro.destroy()
            except Exception:
                pass
            self._intro_cv = None
            if not getattr(self, '_main_built', False):
                self._main_built = True; self._build_main()

    def _build_main(self):
        self._build_topbar()
        # asistan bildirim cubugu (yeni mesaj gelince yanip soner)
