    def _build_readouts(self, parent):
        row = ctk.CTkFrame(parent, fg_color="transparent"); row.pack(fill="x", pady=(0, 8))
        self.cards = {}; self.card_units = {}
        for key, title, unit in [("R", "R (ANLIK)", "ohm"), ("drr", "dR/R0", "%"),
                                 ("maxdrr", "MAKS dR/R0", "%"), ("R0", "R0 (TABAN)", "ohm")]:
            card = ctk.CTkFrame(row, fg_color=CARD_BG, corner_radius=12)
            card.pack(side="left", expand=True, fill="x", padx=4)
            ctk.CTkLabel(card, text=title, font=("Consolas", 11, "bold"), text_color=ACCENT
                         ).pack(pady=(8, 0))
            val = ctk.CTkLabel(card, text="--", font=("Consolas", 21, "bold"),
                               text_color=("#c4b5fd" if key == "drr" else "#efeaff"))
            val.pack()
            ulab = ctk.CTkLabel(card, text=unit, font=("Consolas", 10), text_color="#9b93b8")
            ulab.pack(pady=(0, 8))
            self.cards[key] = val; self.card_units[key] = (ulab, unit)

    def _card(self, key, value, comp=False):
        if key not in self.cards:
            return
        base = self.card_units[key][1]
        if value is None or (isinstance(value, float) and np.isnan(value)):
            self.cards[key].configure(text="--"); return
        if base == "%":
            self.cards[key].configure(text="%.1f" % value)
            self.card_units[key][0].configure(text="%"); return
        ax = abs(value); pre = ""
        for thr, p in _SI:
            if ax >= thr:
                value = value / thr; pre = p; break
        self.cards[key].configure(text="%.3g" % value,
                                  text_color=WARN_RED if comp else "#efeaff")
        self.card_units[key][0].configure(text=(pre + base) if pre else base)

    def _build_plot(self, parent):
        frame = ctk.CTkFrame(parent, fg_color=CARD_BG, corner_radius=12)
        frame.pack(fill="both", expand=True, pady=4)
        self.fig = Figure(figsize=(6, 2.9), dpi=100, facecolor=PLOT_BG)
        self.ax = self.fig.add_subplot(111); self._style_axes(); self.fig.tight_layout(pad=2.0)
        self.canvas = FigureCanvasTkAgg(self.fig, master=frame)
        self.canvas.get_tk_widget().pack(fill="both", expand=True, padx=8, pady=8)
        self.canvas.draw()

    def _style_axes(self, title=None, xlabel="zaman  t  [s]", ylabel="dR/R0  [%]"):
        ax = self.ax; ax.clear(); ax.set_facecolor(PLOT_BG)
        for s in ax.spines.values():
            s.set_color(GRID_CLR)
        ax.tick_params(colors="#9b93b8", labelsize=8)
        ax.grid(True, color=GRID_CLR, linewidth=0.6, alpha=0.7)
        ax.set_xlabel(xlabel, color="#9b93b8", fontsize=9)
        ax.set_ylabel(ylabel, color="#c4b5fd", fontsize=9)
        nm = self.fields["name"].get().strip() if hasattr(self, "fields") else ""
        ax.set_title(title or ("dR/R0 - zaman  -  %s" % nm if nm else "dR/R0 - zaman"),
                     color=ACCENT, fontsize=10, fontweight="bold")

