    def open_safety(self):
        if not self.connected:
            self.log("Once cihaza baglanin."); return
        win = ctk.CTkToplevel(self); win.title("Guvenlik Kontrolu"); win.geometry("600x560")
        win.transient(self)
        try:
            win.after(250, lambda: win.iconbitmap(self._ico_path)
                      if (self._ico_path and os.name == "nt") else None)
        except Exception:
            pass
        ctk.CTkLabel(win, text="GUVENLIK KONTROL LISTESI", font=("Consolas", 16, "bold"),
                     text_color=WARN_RED).pack(pady=(16, 2))
        ctk.CTkLabel(win, text="Olcume baslamadan once tum maddeleri okuyup isaretleyin.",
                     font=("Consolas", 11), text_color="#cdc6e6").pack(pady=(0, 8))
        frame = ctk.CTkScrollableFrame(win, fg_color=PANEL_BG, corner_radius=10)
        frame.pack(fill="both", expand=True, padx=14, pady=6)
        vars_ = []; ok_btn = {"b": None}

        def update_ok():
            ok_btn["b"].configure(state="normal" if all(v.get() for v in vars_) else "disabled")

        for item in SAFETY_ITEMS:
            v = ctk.BooleanVar(value=False); vars_.append(v)
            rowf = ctk.CTkFrame(frame, fg_color="transparent"); rowf.pack(fill="x", padx=8, pady=7, anchor="w")
            ctk.CTkCheckBox(rowf, text="", variable=v, command=update_ok, width=26
                            ).pack(side="left", padx=(0, 8))
            ctk.CTkLabel(rowf, text=item, font=("Consolas", 12), wraplength=500,
                         justify="left", anchor="w").pack(side="left", fill="x", expand=True)

        def confirm():
            from tkinter import messagebox
            if messagebox.askyesno("Emin misiniz?",
                                   "Tum guvenlik adimlarini tamamladiniz mi?\n"
                                   "Olcume / background almaya baslamak uzeresiniz.", parent=win):
                self.safety_ok = True
                self.safety_pill.configure(text=" Guvenlik: ONAYLANDI ", fg_color="#1c4a2e",
                                           text_color="#9fe0b8")
                self.log("Guvenlik kontrolu onaylandi."); self._update_buttons(); win.destroy()

        ok_btn["b"] = ctk.CTkButton(win, text="TAMAM", width=200, height=42,
                                    font=("Consolas", 15, "bold"), fg_color=OK_GREEN,
                                    hover_color="#349a66", text_color="white",
                                    command=confirm, state="disabled")
        ok_btn["b"].pack(pady=12)
        win.after(120, win.grab_set)

    # --------------------------------------------- TANILAMA SIHIRBAZI
    def open_diagnostics(self):
        if not self.connected:
            self.log("Once cihaza baglanin."); return
        if self.worker and self.worker.is_alive():
            self.log("Once devam eden islemi bitirin."); return
        win = ctk.CTkToplevel(self); win.title("Tanilama Sihirbazi"); win.geometry("640x600")
        win.transient(self)
        try:
            win.after(250, lambda: win.iconbitmap(self._ico_path)
                      if (self._ico_path and os.name == "nt") else None)
        except Exception:
            pass
        ctk.CTkLabel(win, text="TANILAMA SIHIRBAZI", font=("Consolas", 16, "bold"),
                     text_color="#b7a7e0").pack(pady=(14, 0))
        ctk.CTkLabel(win, text="Kontak/kacak mi, gercek numune direnci mi? 3 adimda kontrol et.",
                     font=("Consolas", 11), text_color="#cdc6e6").pack(pady=(0, 8))
        steps = [
            ("open", "1) ACIK DEVRE  -  Problari birbirine DEGDIRMEDEN havada/acik birak.",
             "Beklenen: cok yuksek direnc (dusuk kacak)."),
            ("short", "2) KISA DEVRE  -  Dort probu birbirine kisa devre yap.",
             "Beklenen: cok dusuk direnc (sadece kablo/kontak)."),
            ("ref", "3) 1 MOhm REFERANS  -  Bilinen 1 MOhm direnci bagla.",
             "Beklenen: ~1 MOhm (+/- %5)."),
        ]
        self._diag_widgets = {}
        for key, title, hint in steps:
            fr = ctk.CTkFrame(win, fg_color=CARD_BG, corner_radius=10)
            fr.pack(fill="x", padx=14, pady=6)
            ctk.CTkLabel(fr, text=title, font=("Consolas", 12, "bold"), anchor="w",
                         wraplength=560, justify="left").pack(fill="x", padx=10, pady=(8, 0))
            ctk.CTkLabel(fr, text=hint, font=("Consolas", 10), text_color="#9b93b8",
                         anchor="w", wraplength=560, justify="left").pack(fill="x", padx=10)
            row = ctk.CTkFrame(fr, fg_color="transparent"); row.pack(fill="x", padx=10, pady=(2, 8))
            btn = ctk.CTkButton(row, text="Bu adimi olc", width=120,
                                fg_color=ACCENT, hover_color="#7c3aed",
                                command=lambda k=key: self._diag_run(k))
            btn.pack(side="left")
            res = ctk.CTkLabel(row, text="-- henuz olculmedi --", font=("Consolas", 11),
                               text_color="#cdc6e6", anchor="w", justify="left", wraplength=420)
            res.pack(side="left", padx=10, fill="x", expand=True)
            self._diag_widgets[key] = {"btn": btn, "res": res}
        self._diag_summary = ctk.CTkLabel(win, text="", font=("Consolas", 11, "bold"),
                                          text_color=GOLD, wraplength=600, justify="left")
        self._diag_summary.pack(fill="x", padx=14, pady=(2, 6))
        self._diag_open = True; self._diag_results = {}
        self._diag_win = win

        def on_close():
            self._diag_open = False
            try:
                self.worker = None; self._update_buttons()
            except Exception:
                pass
            win.destroy()
        win.protocol("WM_DELETE_WINDOW", on_close)
        self.after(120, self._diag_poll)
        win.after(150, win.grab_set)

    def _diag_run(self, step):
        if self.worker and self.worker.is_alive():
            self.log("Tanilama: once devam eden olcum bitsin."); return
        for k in self._diag_widgets:
            self._diag_widgets[k]["btn"].configure(state="disabled")
        self._diag_widgets[step]["res"].configure(text="olculuyor...", text_color="#cdc6e6")
        self.worker = DiagWorker(self.smu, step, self.diag_q,
                                 nplc=self._get_float("nplc", 1.0),
                                 settle=max(0.02, self._get_float("interval", 0.05)))
        self.worker.start(); self._update_buttons()

    def _diag_poll(self):
        if not getattr(self, "_diag_open", False):
            return
        try:
            while True:
                kind, d = self.diag_q.get_nowait()
                if kind == "diag":
                    self._diag_done(d)
        except queue.Empty:
            pass
        self.after(120, self._diag_poll)

    def _diag_done(self, d):
        step = d.get("step"); w = self._diag_widgets.get(step)
        self.worker = None; self._update_buttons()
        if not w:
            return
        for k in self._diag_widgets:
            self._diag_widgets[k]["btn"].configure(state="normal")
        if d.get("error"):
            w["res"].configure(text="Hata: %s" % d["error"], text_color=WARN_RED); return
        R = d.get("R"); aux = d.get("aux")
        if step == "open":
            ok = (R is None) or (R > 1e9) or (abs(aux) < 1e-9)
            txt = "R_acik = %s  (kacak ~%s)\n%s" % (eng(R, "ohm"), eng(aux, "A"),
                  "Iyi: kacak dusuk." if ok else "Dikkat: kacak/parazit yuksek; yalitim/kabloyu kontrol et.")
            self._diag_results["open"] = ok
        elif step == "short":
            ok = abs(R) < 10
            txt = "R_kisa = %s\n%s" % (eng(R, "ohm"),
                  "Iyi: kontak/kablo direnci dusuk." if ok else
                  "Dikkat: kontak direnci yuksek; problari/baglantilari kontrol et.")
            self._diag_results["short"] = ok
        else:  # ref
            err = (R - 1e6) / 1e6 * 100 if R else float("nan")
            ok = abs(err) <= 5
            txt = "R_olculen = %s  (1 MOhm'dan sapma %% %.1f)\n%s" % (eng(R, "ohm"), err,
                  "Iyi: sistem dogru olcuyor." if ok else
                  "Dikkat: sapma buyuk; kalibrasyon/kontak/compliance kontrol.")
            self._diag_results["ref"] = ok
        w["res"].configure(text=txt, text_color=(OK_GREEN if self._diag_results.get(step) else GOLD))
        self.log("Tanilama [%s]: %s" % (step, txt.replace("\n", " ")))
        self._diag_update_summary()

    def _diag_update_summary(self):
        r = self._diag_results
        if len(r) < 3:
            self._diag_summary.configure(
                text="Uc adimi da olcunce genel yorum burada cikar.", text_color="#9b93b8")
            return
        if all(r.values()):
            self._diag_summary.configure(
                text="SONUC: Sistem saglikli. Kacak dusuk, kontaklar iyi, referans dogru. "
                     "Olculen yuksek dirençler gercek numune direncidir.", text_color=OK_GREEN)
        elif not r.get("open", True):
            self._diag_summary.configure(
                text="SONUC: Acik devrede kacak yuksek. Yuksek dirençli numune olcumlerin "
                     "kacak akimdan etkileniyor olabilir; yalitim/kabloyu iyilestir.", text_color=WARN_RED)
        elif not r.get("short", True):
            self._diag_summary.configure(
                text="SONUC: Kisa devrede direnc yuksek. Kontak direnci sorunu var; "
                     "prob temasini ve kablolari kontrol et.", text_color=WARN_RED)
        else:
            self._diag_summary.configure(
                text="SONUC: Referans sapmasi buyuk. Kalibrasyon ya da kontak/compliance "
                     "ayarini gozden gecir.", text_color=WARN_RED)

    # --------------------------------------------- ASISTAN
    def _build_assistant_tab(self, tab):
        wrap = ctk.CTkFrame(tab, fg_color="transparent"); wrap.pack(fill="both", expand=True, padx=6, pady=6)
        ctk.CTkLabel(wrap, text="ASISTAN  -  Batuhan (cevrimdisi yonlendirme)",
                     font=("Consolas", 13, "bold"), text_color=ACCENT, anchor="w"
                     ).pack(fill="x", pady=(2, 6))
        self.chat = ctk.CTkTextbox(wrap, font=("Consolas", 12), fg_color="#0f1316",
                                   text_color="#cdc6e6", corner_radius=12, wrap="word")
        self.chat.pack(fill="both", expand=True); self.chat.configure(state="disabled")
        quick = ctk.CTkFrame(wrap, fg_color="transparent"); quick.pack(fill="x", pady=6)
        for label, qq in [("Compliance?", "compliance nedir"), ("Mod secimi?", "hangi modu sececegim"),
                          ("Error bar?", "error bar standart sapma nedir"), ("Background?", "background nedir"),
                          ("Guvenlik?", "guvenlik tehlike"), ("Cihaz yok", "cihaz bulunamadi")]:
            ctk.CTkButton(quick, text=label, height=28, font=("Consolas", 11), fg_color="#33414a",
                          hover_color="#3d4f59", command=lambda q=qq: self._ask(q)).pack(side="left", padx=3)
        row = ctk.CTkFrame(wrap, fg_color="transparent"); row.pack(fill="x")
        self.ask_entry = ctk.CTkEntry(row, font=("Consolas", 12),
                                      placeholder_text="Sorunuzu yazin... (orn: dongu nedir, gauge factor, dr/r0 makul mu)")
        self.ask_entry.pack(side="left", fill="x", expand=True, padx=(0, 6), pady=4)
        self.ask_entry.bind("<Return>", lambda e: self._ask())
        ctk.CTkButton(row, text="Gonder", width=90, height=34, font=("Consolas", 13, "bold"),
                      fg_color=ACCENT, hover_color="#7c3aed", command=self._ask).pack(side="right", pady=4)
        self._chat_add("Batuhan", self.assistant.reply("merhaba", self._assist_ctx()))

    def _assist_ctx(self):
        ctx = {"first": self.user["first"], "last": None, "stats": None, "connected": self.connected}
        try:
            ctx["stats"] = self.store.user_stats(self.user["id"])
            ms = self.store.user_measurements(self.user["id"], 1)
            ctx["last"] = ms[0] if ms else None
        except Exception:
            pass
        if ctx["last"] is None and self.sample and "R_fit" in self.sample:
            ctx["last"] = (self.sample.get("name", "numune"), self.sample["mode"],
                           self.sample.get("R_fit"), self.sample.get("Rs"), None, None, None, 0)
        return ctx

    def _chat_add(self, who, msg):
        if not hasattr(self, "chat"):
            return
        self.chat.configure(state="normal")
        self.chat.insert("end", "%s%s\n\n" % (">> SIZ: " if who == "Siz" else ">> BATUHAN: ", msg))
        self.chat.see("end"); self.chat.configure(state="disabled")
        if who != "Siz":
            self._notify_assistant()

    def _ask(self, preset=None):
        text = preset if preset is not None else self.ask_entry.get().strip()
        if not text:
            return
        self.ask_entry.delete(0, "end"); self._chat_add("Siz", text)
        self._chat_add("Batuhan", self.assistant.reply(text, self._assist_ctx()))

    # --------------------------------------------- PROFIL
    def _build_profile_tab(self, tab):
        wrap = ctk.CTkFrame(tab, fg_color="transparent"); wrap.pack(fill="both", expand=True, padx=6, pady=6)
        head = ctk.CTkFrame(wrap, fg_color="transparent"); head.pack(fill="x")
        ctk.CTkLabel(head, text="PROFIL  -  %s %s" % (self.user["first"], self.user["last"]),
                     font=("Consolas", 15, "bold"), text_color=ACCENT, anchor="w").pack(side="left", pady=4)
        ctk.CTkButton(head, text="Yenile", width=90, command=self._refresh_profile,
                      fg_color=ACCENT, hover_color="#7c3aed").pack(side="right")

        # Tercihler kutusu
        prefs = self.store.get_prefs(self.user["id"])
        pf = ctk.CTkFrame(wrap, fg_color=CARD_BG, corner_radius=12); pf.pack(fill="x", pady=(6, 4))
        topf = ctk.CTkFrame(pf, fg_color="transparent"); topf.pack(fill="x", padx=10, pady=(8, 2))
        self.pref_enabled = ctk.BooleanVar(value=bool(prefs.get("enabled", False)))
        ctk.CTkCheckBox(topf, text="Profil tercihlerimi kullan", variable=self.pref_enabled,
                        font=("Consolas", 12, "bold"), command=self._toggle_prefs).pack(side="left")
        ctk.CTkLabel(topf, text="(isaretliyse asagidaki varsayilanlar girise otomatik yuklenir)",
                     font=("Consolas", 10), text_color="#9b93b8").pack(side="left", padx=8)
        gf = ctk.CTkFrame(pf, fg_color="transparent"); gf.pack(fill="x", padx=10, pady=(2, 10))
        self.pref_widgets = {}
        def pe(col, key, label, default):
            ctk.CTkLabel(gf, text=label, font=("Consolas", 11)).grid(row=0, column=col, sticky="w", padx=4, pady=4)
            e = ctk.CTkEntry(gf, width=72, font=("Consolas", 12)); e.insert(0, str(prefs.get(key, default)))
            e.grid(row=0, column=col + 1, padx=4, pady=4); self.pref_widgets[key] = e
        pe(0, "bias", "Bias [V]:", 1.0)
        pe(2, "compliance_i", "Comp [A]:", 0.01)
        pe(4, "nplc", "NPLC:", 1)
        pe(6, "interval", "Aralik [s]:", 0.05)
        pe(8, "cyc_amp", "Dongu genlik[mm]:", 8)
        pe(10, "cyc_n", "Dongu sayisi:", 5)
        ctk.CTkButton(gf, text="Kaydet ve Uygula", command=self._save_prefs, fg_color=OK_GREEN,
                      hover_color="#349a66", text_color="white", font=("Consolas", 12, "bold")
                      ).grid(row=1, column=0, columnspan=4, padx=8, pady=(8, 4), sticky="w")
        self._toggle_prefs()

        self.profile_box = ctk.CTkTextbox(wrap, font=("Consolas", 12), fg_color="#0f1316",
                                          text_color="#cdc6e6", corner_radius=12, wrap="word")
        self.profile_box.pack(fill="both", expand=True, pady=(8, 0)); self.profile_box.configure(state="disabled")
        self._refresh_profile()

    def _toggle_prefs(self):
        state = "normal" if self.pref_enabled.get() else "disabled"
        try:
            for w in self.pref_widgets.values():
                w.configure(state=state)
        except Exception:
            pass

    def _read_prefs_form(self):
        def g(k, d):
            try:
                return float(self.pref_widgets[k].get())
            except Exception:
                return d
        return {"enabled": bool(self.pref_enabled.get()),
                "bias": g("bias", 1.0), "compliance_i": g("compliance_i", 0.01),
                "nplc": g("nplc", 1), "interval": g("interval", 0.05),
                "cyc_amp": g("cyc_amp", 8), "cyc_n": int(g("cyc_n", 5))}

    def _save_prefs(self):
        prefs = self._read_prefs_form()
        self.store.set_prefs(self.user["id"], prefs)
        if prefs["enabled"]:
            self._apply_prefs()
            self.log("Profil tercihleri kaydedildi ve olcum ayarlarina uygulandi.")
        else:
            self.log("Profil tercihleri kaydedildi (kullanim kapali).")

    def _apply_prefs(self, initial=False):
        prefs = self.store.get_prefs(self.user["id"])
        if not prefs.get("enabled"):
            return
        try:
            for k in ("bias", "compliance_i", "nplc", "interval"):
                if k in self.fields and k in prefs:
                    self.fields[k].delete(0, "end"); self.fields[k].insert(0, str(prefs[k]))
            for k in ("cyc_amp", "cyc_n"):
                if hasattr(self, "mfields") and k in self.mfields and k in prefs:
                    self.mfields[k].delete(0, "end")
                    self.mfields[k].insert(0, str(int(prefs[k]) if k == "cyc_n" else prefs[k]))
            if initial:
                self.log("Profil tercihleriniz olcum/dongu ayarlarina yuklendi.")
        except Exception:
            pass

    def _refresh_profile(self):
        st = self.store.user_stats(self.user["id"]); L = []
        L.append("KULLANICI : %s %s" % (self.user["first"], self.user["last"]))
        L.append("Toplam kayitli olcum : %d" % st["count"])
        if st["count"] == 0:
            L += ["", "Henuz olcum kaydiniz yok. Ilk olcumunuzu alin; tamamlaninca",
                  "buraya kaydedilir ve size ozel oneriler belirir.", "",
                  "=== GENEL IPUCLARI ==="]
            for tip in self._general_tips():
                L.append("  * " + tip)
            self._set_profile("\n".join(L)); return
        if st["first_date"]:
            L.append("Ilk olcum tarihi    : %s" % st["first_date"][:10])
        if st["last"]:
            L.append("Son olcum tarihi    : %s" % (st["last"][5] or "")[:10])
        L.append("Farkli numune sayisi : %d" % len(st["samples"]))
        if st["reps"]:
            L.append("Ortalama tekrar      : %.1f" % float(np.mean(st["reps"])))
        L += ["", "=== OLCUM TURU ==="]
        total = sum(st["modes"].values())
        for k, v in sorted(st["modes"].items(), key=lambda x: -x[1]):
            L.append("  %-9s : %3d  (%%%d)" % (k, v, round(100 * v / total)))
        if st["rs"]:
            arr = np.array(st["rs"])
            L += ["", "=== MAKS dR/R0 [%] ===",
                  "  ortalama : %.4g %%" % arr.mean(),
                  "  medyan   : %.4g %%" % np.median(arr),
                  "  min-max  : %.4g  ...  %.4g %%" % (arr.min(), arr.max())]
            if st["area"]:
                L.append("  tahmini calisma alani: %s" % st["area"])
        if st["samples"]:
            L += ["", "=== EN COK OLCULEN NUMUNELER ==="]
            for name, cnt in sorted(st["samples"].items(), key=lambda x: -x[1])[:5]:
                L.append("  %-22s : %d kez" % (str(name)[:22], cnt))
        L += ["", "=== SON OLCUMLER ==="]
        for r in st["rows"][:8]:
            L.append("  %-22s R0=%-10.4g maksdR/R0=%-7.4g%% %s"
                     % (str(r[0])[:22], r[2] or float("nan"), r[3] or float("nan"), (r[5] or "")[:10]))
        L += ["", "=== SIZE OZEL ONERILER ==="]
        for rec in self._recommendations(st):
            L.append("  * " + rec)
        L += ["", "=== GENEL IPUCLARI ==="]
        for tip in self._general_tips():
            L.append("  * " + tip)
        self._set_profile("\n".join(L))

    def _recommendations(self, st):
        recs = []
        rs = st.get("rs") or []      # burada rs = maks dR/R0 [%] listesi
        if rs:
            arr = np.array(rs, dtype=float); m = float(arr.mean())
            if m < 5:
                recs.append("Maks dR/R0 ortalamaniz dusuk (%.1f%%); numune yeterince gerilmiyor ya da "
                            "elektrot temasi zayif olabilir. Dongu genligini artirin, bakir folyo temasini kontrol edin." % m)
            elif m > 300:
                recs.append("Cok yuksek dR/R0 ortalamasi (%.0f%%); guclu yanit. Gauge factor'u dogru cikarmak "
                            "icin uygulanan gerinimi (genlik/L0) net girin." % m)
            else:
                recs.append("dR/R0 yanitiniz makul aralikta (ort %.1f%%). Tekrarlanabilirlik icin ayni numuneyi "
                            "3-5 kez dongusel olcun." % m)
            if len(rs) >= 3 and (arr.std() / (m or 1.0)) > 0.25:
                recs.append("Olcumler arasi dR/R0 sacilimi yuksek; kiskac kaymasi/temas degisimi olabilir. "
                            "Numune ucunu daha iyi sabitleyin ve ayni hizda olcun.")
        recs.append("Dongusel testte tepe dR/R0'in donguden donguye sabit kalmasi iyi tekrarlanabilirlik/"
                    "kararlilik; germe ve gevsetme egrileri arasindaki fark histerezistir.")
        if st["count"] >= 5:
            recs.append("Karsilastir sekmesinde farkli numunelerin dR/R0-zaman egrilerini ust uste koyup "
                        "duyarlilik/dayaniklilik kiyaslayin.")
        if not recs:
            recs.append("Daha fazla dongusel olcum biriktikce oneriler kisisellesir.")
        return recs

    def _general_tips(self):
        return ["Olcume numune GEVSEKKEN baslayin; taban (R0) orada alinir.",
                "Bias dusuk (~1 V), compliance guvenli (~10 mA); olcum sirasinda aktuatorler sabit.",
                "Dongu genligi / L0 = gerinim; gauge factor icin bunu dogru girin.",
                "Elektrot (bakir folyo) temasini ve kiskac sikiligini her olcum oncesi kontrol edin.",
                "Tekrarlanabilirlik icin ayni numuneyi 3-5 kez dongusel olcun; CSV'leri tarih-saatli saklayin."]

    def _set_profile(self, text):
        self.profile_box.configure(state="normal"); self.profile_box.delete("1.0", "end")
        self.profile_box.insert("1.0", text); self.profile_box.configure(state="disabled")

