    @staticmethod
    def _base_name(sample):
        toks = str(sample or "").split("_")
        return "_".join(toks[2:]) if len(toks) >= 3 else str(sample or "")

    def _refresh_archive(self):
        for w in self.arch_list.winfo_children():
            w.destroy()
        self.arch_selected = {}
        try:
            days = int(self.arch_days.get() or 0)
        except Exception:
            days = 0
        rows = self.store.list_measurements(self.user["id"], self.arch_sample.get().strip(),
                                            self.arch_mode.get(), days, self.arch_all.get(), 200)
        if not rows:
            ctk.CTkLabel(self.arch_list, text="Kayit bulunamadi.", font=("Consolas", 12),
                         text_color="#9b93b8").pack(pady=20); return
        for r in rows:
            mid, uname, sample, mode, r_fit, rs, rho, created, comp, has_data = r
            rowf = ctk.CTkFrame(self.arch_list, fg_color=CARD_BG, corner_radius=8)
            rowf.pack(fill="x", padx=4, pady=3)
            var = ctk.BooleanVar(value=False); self.arch_selected[mid] = var
            ctk.CTkCheckBox(rowf, text="", variable=var, width=24).pack(side="left", padx=(8, 2), pady=6)
            base = self._base_name(sample)
            prefix = ("%s | " % (uname or "?")) if self.arch_all.get() else ""
            line1 = "%s%s" % (prefix, base)
            line2 = "%s  |  %s  |  R=%s  Rs=%s%s" % ((created or "")[:16], mode,
                                                    eng(r_fit, "ohm"), (("%.1f%%" % rs) if rs is not None else "--"),
                                                    ("  [compliance]" if comp else ""))
            cell = ctk.CTkFrame(rowf, fg_color="transparent"); cell.pack(side="left", fill="x", expand=True, padx=4)
            ctk.CTkLabel(cell, text=line1, font=("Consolas", 12, "bold"), anchor="w",
                         text_color="#eaf3f4", justify="left").pack(fill="x")
            ctk.CTkLabel(cell, text=line2, font=("Consolas", 10), anchor="w",
                         text_color="#9fb6bc", justify="left").pack(fill="x")
            st = "normal" if has_data else "disabled"
            ctk.CTkButton(rowf, text="Rapor", width=58, height=26, font=("Consolas", 10),
                          fg_color="#33414a", hover_color="#3d4f59", state=st,
                          command=lambda i=mid: self._arch_report(i)).pack(side="right", padx=3, pady=4)
            ctk.CTkButton(rowf, text="+Karsi", width=58, height=26, font=("Consolas", 10),
                          fg_color="#33414a", hover_color="#3d4f59", state=st,
                          command=lambda i=mid: self._arch_compare(i)).pack(side="right", padx=3, pady=4)
            ctk.CTkButton(rowf, text="Duzenle", width=70, height=26, font=("Consolas", 10),
                          fg_color="#5a4b8a", hover_color="#6d5ca3", text_color="white", state=st,
                          command=lambda i=mid: self._arch_edit(i)).pack(side="right", padx=3, pady=4)
            ctk.CTkButton(rowf, text="CSV", width=48, height=26, font=("Consolas", 10),
                          fg_color="#33414a", hover_color="#3d4f59", state=st,
                          command=lambda i=mid: self._arch_csv(i)).pack(side="right", padx=3, pady=4)
            ctk.CTkButton(rowf, text="Goruntule", width=80, height=26, font=("Consolas", 10),
                          fg_color=ACCENT, hover_color="#7c3aed", state=st,
                          command=lambda i=mid: self._arch_view(i)).pack(side="right", padx=3, pady=4)

    def _arch_select_all(self, val):
        for v in self.arch_selected.values():
            v.set(val)

    def _selected_ids(self):
        return [mid for mid, v in self.arch_selected.items() if v.get()]

    # ---- toplu disa aktarma ----
    def _bulk_export(self, fmt):
        ids = self._selected_ids()
        if not ids:
            self.log("Once listeden olcum sec (kutucuklar)."); return
        data = [self.store.get_measurement(i) for i in ids]
        data = [d for d in data if d]
        if not data:
            self.log("Secili kayitlarin tam verisi yok."); return
        from tkinter import filedialog
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        if fmt == "csv":
            path = filedialog.asksaveasfilename(defaultextension=".csv",
                                                initialfile="toplu_ozet_%s.csv" % stamp,
                                                filetypes=[("CSV", "*.csv")])
            if path:
                self._export_csv_summary(data, path)
        elif fmt == "excel":
            path = filedialog.asksaveasfilename(defaultextension=".xlsx",
                                                initialfile="toplu_%s.xlsx" % stamp,
                                                filetypes=[("Excel", "*.xlsx")])
            if path:
                self._export_excel(data, path)
        elif fmt == "pdf":
            path = filedialog.asksaveasfilename(defaultextension=".pdf",
                                                initialfile="toplu_rapor_%s.pdf" % stamp,
                                                filetypes=[("PDF", "*.pdf")])
            if path:
                self._export_pdf_multi(data, path)

    def _export_csv_summary(self, data, path):
        try:
            with open(path, "w", newline="", encoding="utf-8") as f:
                w = csv.writer(f); w.writerow(["# B Strain Sensor - Toplu ozet"])
                w.writerow(["numune", "mod", "tekrar", "R0[ohm]", "dR[ohm]", "maks_dRR[%]",
                            "GF", "R0_ham[ohm]", "compliance_nokta", "nokta"])
                for s in data:
                    w.writerow([s.get("name", "?"), s.get("mode", "?"), s.get("n_repeats", ""),
                                "%.6g" % (s.get("R_fit") or float("nan")),
                                "%.6g" % (s.get("dR") or 0),
                                "%.6g" % (s.get("Rs") or float("nan")),
                                ("%.6g" % s["rho"]) if s.get("rho") else "",
                                "%.6g" % (s.get("R_raw") or float("nan")),
                                s.get("comp_hits", 0), s.get("n", "")])
            self.log("Toplu CSV ozet kaydedildi (%d olcum): %s" % (len(data), path))
        except Exception as e:
            self.log("Toplu CSV hatasi: %s" % e)

    def _export_excel(self, data, path):
        try:
            import openpyxl
        except Exception:
            self.log("Excel icin 'openpyxl' gerekli. Kurmak icin: pip install openpyxl"); return
        try:
            from openpyxl import Workbook
            wb = Workbook()
            ws0 = wb.active; ws0.title = "Ozet"
            ws0.append(["numune", "mod", "tekrar", "R0[ohm]", "dR[ohm]", "maks_dRR[%]",
                        "GF", "R0_ham[ohm]", "compliance", "nokta"])
            for s in data:
                ws0.append([s.get("name", "?"), s.get("mode", "?"), s.get("n_repeats", ""),
                            s.get("R_fit"), s.get("dR"), s.get("Rs"), s.get("rho"),
                            s.get("R_raw"), s.get("comp_hits", 0), s.get("n", "")])
            used = {"Ozet"}
            for idx, s in enumerate(data, 1):
                base = self._base_name(s.get("name", "olcum")) or ("olcum%d" % idx)
                title = base[:25] or ("olcum%d" % idx)
                t = title; k = 1
                while t in used:
                    k += 1; t = (title[:22] + "_%d" % k)
                used.add(t)
                ws = wb.create_sheet(t)
                iso = s.get("iso", s.get("mode") == "isource")
                ws.append(["index", "set", "I_bg[A]", "V_bg[V]", "I_ham[A]", "V_ham[V]",
                           "I_temiz[A]", "V_temiz[V]", "std", "R_temiz[ohm]"])
                n = s.get("n", 0)
                for i in range(n):
                    xc = s["Xc"][i]; yc = s["Yc"][i]
                    R = (yc / xc) if xc else ""
                    std = s["YEc"][i] if iso else s["XEc"][i]
                    ws.append([i, s["sweep"][i], s["Ib"][i], s["Vb"][i], s["Xr"][i], s["Yr"][i],
                               xc, yc, std, R])
            wb.save(path)
            self.log("Toplu Excel kaydedildi (%d sayfa): %s" % (len(data), path))
        except Exception as e:
            self.log("Excel hatasi: %s" % e)

    def _export_pdf_multi(self, data, path):
        try:
            from matplotlib.backends.backend_pdf import PdfPages
            with PdfPages(path) as pdf:
                for s in data:
                    fig = self._report_figure(s)
                    pdf.savefig(fig)
            self.log("Toplu PDF kaydedildi (%d sayfa): %s" % (len(data), path))
        except Exception as e:
            self.log("Toplu PDF hatasi: %s" % e)

    # ---- yedek / ice aktar ----
    def _backup_db(self):
        from tkinter import filedialog
        path = filedialog.asksaveasfilename(defaultextension=".sqlite",
                                            initialfile="b4pp_yedek_%s.sqlite" % datetime.now().strftime("%Y%m%d_%H%M%S"),
                                            filetypes=[("SQLite", "*.sqlite"), ("Tum dosyalar", "*.*")])
        if not path:
            return
        if self.store.backup(path):
            self.log("Veritabani yedeklendi: %s" % path)
        else:
            self.log("Yedekleme basarisiz.")

    def _import_db(self):
        from tkinter import filedialog, messagebox
        path = filedialog.askopenfilename(filetypes=[("SQLite", "*.sqlite"), ("Tum dosyalar", "*.*")])
        if not path:
            return
        if not messagebox.askyesno("Ice aktar",
                                   "Secili veritabani mevcut verinin UZERINE yazilacak.\n"
                                   "(Once 'Yedekle' ile mevcut veriyi saklayabilirsin.)\nDevam edilsin mi?"):
            return
        if self.store.import_db(path):
            self.user["id"] = self.store.get_or_create_user(self.user["first"], self.user["last"])
            self._refresh_archive(); self._refresh_profile()
            self.log("Veritabani ice aktarildi: %s" % path)
        else:
            self.log("Ice aktarma basarisiz (gecerli bir b4pp veritabani mi?).")

    def _arch_load(self, mid):
        s = self.store.get_measurement(mid)
        if not s:
            self.log("Bu kaydin tam verisi yok (eski kayit olabilir)."); return None
        return s

    def _arch_view(self, mid):
        s = self._arch_load(mid)
        if s:
            self._load_into_plot(s); self.tabs.set("Olcum")
            self.log("Arsivden yuklendi: %s" % s.get("name", "?"))

    def _arch_edit(self, mid):
        s = self._arch_load(mid)
        if s:
            self._ed_load(s); self.tabs.set("Duzenle")

    def _arch_csv(self, mid):
        s = self._arch_load(mid)
        if s:
            self.sample = s; self.last_params = self._params_from_summary(s); self.save_csv()

    def _arch_compare(self, mid):
        s = self._arch_load(mid)
        if s:
            s["_id"] = mid
            if not any(c.get("_id") == mid for c in self.compare):
                self.compare.append(s)
            self._refresh_compare(); self.tabs.set("Karsilastir")
            self.log("Karsilastirmaya eklendi: %s" % s.get("name", "?"))

    def _arch_report(self, mid):
        s = self._arch_load(mid)
        if s:
            self.report_target = s; self._refresh_report(); self.tabs.set("Rapor")

    def _params_from_summary(self, s):
        return {"name": s.get("name", "Numune"), "nplc": s.get("nplc", 1),
                "settle": s.get("settle", 0.05), "thickness": s.get("thickness")}

    def _load_into_plot(self, s):
        self.sample = s; self.last_params = self._params_from_summary(s)
        self.cur_xc = list(s.get("Xc", [])); self.cur_yc = list(s.get("Yc", []))
        self.cur_xr = list(s.get("Xr", [])); self.cur_yr = list(s.get("Yr", []))
        self.cur_xce = list(s.get("XEc", [])); self.cur_yce = list(s.get("YEc", []))
        self.cur_xer = list(s.get("XEr", [])); self.cur_yer = list(s.get("YEr", []))
        self.cur_xb, self.cur_yb = [], []
        self.cur_reps, self.cur_sets = [], list(s.get("sweep", []))
        self.R0 = s.get("R0"); self.max_drr = s.get("max_drr", 0.0) or 0.0
        try:
            base = str(s.get("name", "")).split("_")[-1]
            self.fields["name"].delete(0, "end"); self.fields["name"].insert(0, base)
        except Exception:
            pass
        if self.R0:
            self._card("R0", self.R0)
        self._card("maxdrr", self.max_drr)
        self.btn_csv.configure(state="normal"); self.btn_png.configure(state="normal")
        self._redraw()

