    def _ed_style(self, title=None):
        ax = self.ed_ax; ax.clear(); ax.set_facecolor(PLOT_BG)
        for s in ax.spines.values():
            s.set_color(GRID_CLR)
        ax.tick_params(colors="#9b93b8", labelsize=8)
        ax.grid(True, color=GRID_CLR, linewidth=0.6, alpha=0.7)
        ax.set_xlabel("zaman  t  [s]", color="#9b93b8", fontsize=9)
        ax.set_ylabel("dR/R0  [%]", color="#c4b5fd", fontsize=9)
        nm = (self.ed or {}).get("name", "")
        base = self._base_name(nm) if nm else ""
        ax.set_title(title or ("DUZENLE  -  %s" % base if base else "DUZENLE"),
                     color=ACCENT, fontsize=10, fontweight="bold")

    def _ed_init_selectors(self):
        if self._ed_rect is not None:
            return
        try:
            self._ed_rect = RectangleSelector(self.ed_ax, self._ed_on_box, useblit=True,
                                              button=[1], minspanx=1, minspany=1,
                                              spancoords="pixels", interactive=False,
                                              props=dict(facecolor=ACCENT, edgecolor=GOLD,
                                                         alpha=0.2, fill=True))
            self._ed_rect.set_active(False)
        except Exception as e:
            self._ed_rect = None; self.log("Kutu secici kurulamadi: %s" % e)
        try:
            self._ed_span = SpanSelector(self.ed_ax, self._ed_on_span, "horizontal",
                                         useblit=True, interactive=True,
                                         props=dict(alpha=0.2, facecolor=GOLD))
            self._ed_span.set_active(False)
        except Exception as e:
            self._ed_span = None; self.log("Aralik secici kurulamadi: %s" % e)

    def _ed_set_mode(self, value=None):
        m = {"Gez/Yakinlastir": "pan", "Tek tikla sil": "nokta",
             "Kutu sec": "box", "X-aralik": "xrange"}.get(value or self.ed_seg.get(), "pan")
        self.ed_mode = m
        self._ed_init_selectors()
        # navigasyon araci ile cakismayi onle
        try:
            if m != "pan" and getattr(self.ed_toolbar, "mode", ""):
                # aktif pan/zoom varsa birak
                if self.ed_toolbar.mode:
                    self.ed_toolbar.pan() if "pan" in str(self.ed_toolbar.mode) else self.ed_toolbar.zoom()
        except Exception:
            pass
        if self._ed_rect:
            self._ed_rect.set_active(m == "box")
        if self._ed_span:
            self._ed_span.set_active(m == "xrange")
        self.ed_sel = []; self._ed_xspan = None
        self._ed_draw()

    def _ed_load(self, s):
        if not s or "Xc" not in s:
            self.log("Duzenlenecek veri yok."); return
        self.ed = _copy.deepcopy(s)
        self.ed_orig = _copy.deepcopy(s)
        self.ed_undo = []; self.ed_sel = []; self._ed_xspan = None
        self._ed_recompute(); self._ed_draw(reset_view=True)
        self.log("Duzenleyiciye yuklendi: %s (%d nokta)" % (s.get("name", "?"), len(self.ed["Xc"])))

    def _ed_use_current(self):
        if self.sample and "Xc" in self.sample:
            self._ed_load(self.sample)
        else:
            self.log("Once Olcum sekmesinde bir olcum yapin/yukleyin.")

    def _ed_use_last_archive(self):
        rows = self.store.list_measurements(self.user["id"], "", "hepsi", 0, False, 1)
        if rows and rows[0][9]:
            s = self.store.get_measurement(rows[0][0])
            if s:
                self._ed_load(s); return
        self.log("Yuklenecek (tam verili) arsiv kaydi bulunamadi.")

    def _ed_recompute(self):
        s = self.ed
        if not s:
            return
        Xc = np.array(s.get("Xc", []), float); Yc = np.array(s.get("Yc", []), float)
        Yr = np.array(s.get("Yr", []), float)
        s["n"] = int(len(Xc))
        s["max_drr"] = float(np.max(Yc)) if Yc.size else 0.0; s["Rs"] = s["max_drr"]
        if Yr.size:
            s["R0"] = float(np.median(Yr[:max(1, min(10, Yr.size))])); s["R_fit"] = s["R0"]; s["R_raw"] = s["R0"]
        st = s.get("strain_pct"); s["gauge_factor"] = (s["max_drr"] / st) if (st and st != 0) else None
        s["rho"] = s["gauge_factor"]
        try:
            self.ed_result.configure(
                text="n=%d   R0=%s   maks dR/R0=%.1f%%%s"
                % (s["n"], eng(s.get("R0"), "ohm"), s.get("max_drr", 0.0),
                   ("   GF=%.2f" % s["gauge_factor"]) if s.get("gauge_factor") is not None else ""))
        except Exception:
            pass

    def _ed_draw(self, reset_view=False):
        if not hasattr(self, "ed_ax"):
            return
        xlim = self.ed_ax.get_xlim() if not reset_view else None
        ylim = self.ed_ax.get_ylim() if not reset_view else None
        self._ed_style()
        s = self.ed
        if s and s.get("Xc"):
            Xc = np.array(s["Xc"], float); Yc = np.array(s["Yc"], float)
            self.ed_ax.plot(Xc, Yc, color=ACCENT, lw=1.4, zorder=3)
            self.ed_ax.scatter(Xc, Yc, s=18, color=ACCENT, edgecolors="white",
                               linewidths=0.3, zorder=4, picker=True)
            if self.ed_sel:
                self.ed_ax.scatter(Xc[self.ed_sel], Yc[self.ed_sel], s=140, facecolors="none",
                                   edgecolors=WARN_RED, linewidths=2.0, zorder=6)
            if self._ed_xspan:
                self.ed_ax.axvspan(self._ed_xspan[0], self._ed_xspan[1], color=GOLD, alpha=0.12, zorder=1)
        if not reset_view and xlim and ylim and (xlim != (0.0, 1.0)):
            self.ed_ax.set_xlim(xlim); self.ed_ax.set_ylim(ylim)
        self.ed_canvas.draw_idle()

    def _ed_push_undo(self):
        if self.ed:
            self.ed_undo.append(_copy.deepcopy(self.ed))
            if len(self.ed_undo) > 40:
                self.ed_undo.pop(0)

    _PERPT = ("Xc", "Yc", "XEc", "YEc", "Xr", "Yr", "XEr", "YEr", "reps", "sweep")

    def _ed_delete_indices(self, idxs):
        if not self.ed or not idxs:
            return
        idxs = set(int(i) for i in idxs)
        if len(idxs) >= len(self.ed.get("Xc", [])):
            self.log("Tum noktalar silinemez."); return
        self._ed_push_undo()
        for k in self._PERPT:
            if k in self.ed and isinstance(self.ed[k], list):
                self.ed[k] = [v for j, v in enumerate(self.ed[k]) if j not in idxs]
        self.ed_sel = []; self._ed_recompute(); self._ed_draw()
        self.log("%d nokta silindi. Yeni R=%s" % (len(idxs), eng(self.ed.get("R_fit"), "ohm")))

    def _ed_on_click(self, event):
        if self.ed_mode != "nokta" or not self.ed or event.inaxes != self.ed_ax:
            return
        if event.xdata is None:
            return
        Xc = np.array(self.ed["Xc"], float); Yc = np.array(self.ed["Yc"], float)
        if len(Xc) == 0:
            return
        disp = self.ed_ax.transData.transform(np.column_stack([Xc, Yc]))
        d = np.hypot(disp[:, 0] - event.x, disp[:, 1] - event.y)
        i = int(np.argmin(d))
        if d[i] <= 18:
            self._ed_delete_indices([i])

    def _ed_on_box(self, eclick, erelease):
        if not self.ed:
            return
        x0, x1 = sorted([eclick.xdata, erelease.xdata])
        y0, y1 = sorted([eclick.ydata, erelease.ydata])
        Xc = np.array(self.ed["Xc"], float); Yc = np.array(self.ed["Yc"], float)
        self.ed_sel = [i for i in range(len(Xc))
                       if x0 <= Xc[i] <= x1 and y0 <= Yc[i] <= y1]
        self._ed_draw()
        self.log("%d nokta secildi. 'Secileni sil' ile kaldirabilirsin." % len(self.ed_sel))

    def _ed_on_span(self, xmin, xmax):
        if xmin == xmax:
            self._ed_xspan = None
        else:
            self._ed_xspan = (xmin, xmax)
        self._ed_draw()

    def _ed_delete_selected(self):
        if self.ed_sel:
            self._ed_delete_indices(self.ed_sel)
        else:
            self.log("Once 'Kutu sec' ile nokta secin.")

    def _ed_range_delete(self):
        if not self._ed_xspan or not self.ed:
            self.log("Once 'X-aralik' ile bir aralik secin."); return
        a, b = self._ed_xspan
        Xc = self.ed["Xc"]
        self._ed_delete_indices([i for i in range(len(Xc)) if a <= Xc[i] <= b])
        self._ed_xspan = None

    def _ed_range_keep(self):
        if not self._ed_xspan or not self.ed:
            self.log("Once 'X-aralik' ile bir aralik secin."); return
        a, b = self._ed_xspan
        Xc = self.ed["Xc"]
        self._ed_delete_indices([i for i in range(len(Xc)) if not (a <= Xc[i] <= b)])
        self._ed_xspan = None

    def _ed_undo_action(self):
        if self.ed_undo:
            self.ed = self.ed_undo.pop()
            self.ed_sel = []; self._ed_xspan = None
            self._ed_recompute(); self._ed_draw()
            self.log("Geri alindi.")
        else:
            self.log("Geri alinacak islem yok.")

    def _ed_reset(self):
        if self.ed_orig:
            self.ed = _copy.deepcopy(self.ed_orig)
            self.ed_undo = []; self.ed_sel = []; self._ed_xspan = None
            self._ed_recompute(); self._ed_draw(reset_view=True)
            self.log("Orijinal veriye donuldu.")

    def _ed_visible_copy(self):
        """Sadece gorunen x-araligindaki noktalarla yeni bir kopya."""
        s = _copy.deepcopy(self.ed)
        x0, x1 = self.ed_ax.get_xlim()
        Xc = s.get("Xc", [])
        keep = [i for i in range(len(Xc)) if x0 <= Xc[i] <= x1]
        if len(keep) < len(Xc):
            ks = set(keep)
            for k in self._PERPT:
                if k in s and isinstance(s[k], list):
                    s[k] = [v for j, v in enumerate(s[k]) if j in ks]
        # yeniden hesap
        Xc2 = np.array(s.get("Xc", []), float); Yc2 = np.array(s.get("Yc", []), float)
        s["n"] = len(Xc2)
        if len(Xc2) >= 2:
            s["max_drr"] = float(np.max(Yc2)) if len(Yc2) else 0.0; s["Rs"] = s["max_drr"]
            try:
                s["R0"] = float(np.median(np.array(s["Yr"], float)[:10])); s["R_fit"] = s["R0"]; s["R_raw"] = s["R0"]
            except Exception:
                pass
            _st = s.get("strain_pct"); s["gauge_factor"] = (s["max_drr"]/_st) if (_st and _st!=0) else None
            s["rho"] = s["gauge_factor"]
        return s

    def _ed_payload(self):
        return self._ed_visible_copy() if self.ed_visible_only.get() else _copy.deepcopy(self.ed)

    def _ed_save_archive(self):
        if not self.ed:
            self.log("Once bir olcum yukleyin."); return
        s = self._ed_payload()
        base = self._base_name(s.get("name", "olcum"))
        s["name"] = "%s_%s_%s" % (_safe(self.user["first"]), _safe(self.user["last"]),
                                  _safe(base + "_duzen"))
        self.store.add_measurement(self.user["id"], s)
        try:
            self._refresh_archive()
        except Exception:
            pass
        self.log("Duzenlenmis olcum arsive kaydedildi: %s" % s["name"])

