    # --------------------------------------------- KARSILASTIR
    def _build_compare_tab(self, tab):
        wrap = ctk.CTkFrame(tab, fg_color="transparent"); wrap.pack(fill="both", expand=True, padx=6, pady=6)
        bar = ctk.CTkFrame(wrap, fg_color="transparent"); bar.pack(fill="x")
        ctk.CTkLabel(bar, text="KARSILASTIR", font=("Consolas", 14, "bold"), text_color=ACCENT
                     ).pack(side="left", pady=2)
        ctk.CTkButton(bar, text="Mevcut olcumu ekle", command=self._cmp_add_current, width=150,
                      fg_color=ACCENT, hover_color="#7c3aed").pack(side="left", padx=6)
        ctk.CTkButton(bar, text="Temizle", command=self._cmp_clear, width=80, fg_color=WARN_RED,
                      hover_color="#a8352d").pack(side="left", padx=4)
        ctk.CTkButton(bar, text="Grafik kaydet", command=self._cmp_save_graph, width=120,
                      fg_color="#33414a", hover_color="#3d4f59").pack(side="right", padx=4)
        ctk.CTkButton(bar, text="CSV kaydet", command=self._cmp_save_csv, width=110,
                      fg_color="#33414a", hover_color="#3d4f59").pack(side="right", padx=4)
        ctk.CTkLabel(wrap, text="Arsiv sekmesinden '+Karsi' ile de ekleyebilirsiniz.",
                     font=("Consolas", 10), text_color="#9b93b8", anchor="w").pack(fill="x", pady=(2, 4))
        pf = ctk.CTkFrame(wrap, fg_color=CARD_BG, corner_radius=12); pf.pack(fill="both", expand=True)
        self.cmp_fig = Figure(figsize=(6, 3.0), dpi=100, facecolor=PLOT_BG)
        self.cmp_ax = self.cmp_fig.add_subplot(111); self.cmp_fig.tight_layout(pad=2.0)
        self.cmp_canvas = FigureCanvasTkAgg(self.cmp_fig, master=pf)
        self.cmp_canvas.get_tk_widget().pack(fill="both", expand=True, padx=8, pady=8)
        self.cmp_text = ctk.CTkTextbox(wrap, height=140, font=("Consolas", 11), fg_color="#0f1316",
                                       text_color="#cdc6e6", corner_radius=12, wrap="none")
        self.cmp_text.pack(fill="x", pady=(6, 0)); self.cmp_text.configure(state="disabled")
        self._refresh_compare()

    def _cmp_style(self):
        ax = self.cmp_ax; ax.clear(); ax.set_facecolor(PLOT_BG)
        for s in ax.spines.values():
            s.set_color(GRID_CLR)
        ax.tick_params(colors="#9b93b8", labelsize=8)
        ax.grid(True, color=GRID_CLR, linewidth=0.6, alpha=0.7)
        ax.set_xlabel("zaman t [s]", color="#9b93b8", fontsize=9)
        ax.set_ylabel("dR/R0 [%]", color="#c4b5fd", fontsize=9)
        ax.set_title("Karsilastirma (dR/R0 - zaman)", color=ACCENT, fontsize=10, fontweight="bold")

    def _refresh_compare(self):
        self._cmp_style()
        for i, s in enumerate(self.compare):
            c = CMP_COLORS[i % len(CMP_COLORS)]
            base = str(s.get("name", "?")).split("_")[-1]
            self.cmp_ax.errorbar(s.get("Xc", []), s.get("Yc", []),
                                 yerr=(s.get("YEc") if s.get("iso", True) else None),
                                 xerr=(None if s.get("iso", True) else s.get("XEc")),
                                 fmt="o", ms=4, color=c, ecolor=c, capsize=2, label=base[:16])
            if len(s.get("Xc", [])) >= 2:
                X = np.array(s["Xc"]); m, b = np.polyfit(X, np.array(s["Yc"]), 1)
                xs = np.linspace(X.min(), X.max(), 50)
                self.cmp_ax.plot(xs, m * xs + b, color=c, lw=1.0, alpha=0.8)
        if self.compare:
            self.cmp_ax.legend(fontsize=7, loc="best", facecolor=CARD_BG, edgecolor=GRID_CLR,
                               labelcolor="#cdc6e6")
        self.cmp_canvas.draw_idle()
        # tablo
        lines = ["%-20s %-8s %-12s %-12s %-12s" % ("Numune", "Mod", "R0[ohm]", "maks_dRR[%]", "GF")]
        lines.append("-" * 68)
        for s in self.compare:
            lines.append("%-20s %-8s %-12s %-12s %-12s"
                         % (str(s.get("name", "?")).split("_")[-1][:20], s.get("mode", "?"),
                            fmt_val(s.get("R_fit")), fmt_val(s.get("Rs")), fmt_val(s.get("rho"))))
        if len(self.compare) >= 2:
            rss = [s.get("Rs") for s in self.compare if s.get("Rs") is not None]
            if len(rss) >= 2:
                lines += ["", "maks dR/R0 min=%s  max=%s  oran(max/min)=%.2f"
                          % (fmt_val(min(rss)), fmt_val(max(rss)), max(rss) / max(min(rss), 1e-12))]
        self.cmp_text.configure(state="normal"); self.cmp_text.delete("1.0", "end")
        self.cmp_text.insert("1.0", "\n".join(lines)); self.cmp_text.configure(state="disabled")

    def _cmp_add_current(self):
        if not self.sample or "Xc" not in self.sample:
            self.log("Once bir olcum yapin/yukleyin."); return
        s = dict(self.sample); s["_id"] = "current_%d" % len(self.compare)
        self.compare.append(s); self._refresh_compare()
        self.log("Mevcut olcum karsilastirmaya eklendi.")

    def _cmp_clear(self):
        self.compare = []; self._refresh_compare(); self.log("Karsilastirma temizlendi.")

    def _cmp_save_graph(self):
        if not self.compare:
            self.log("Karsilastirilacak olcum yok."); return
        from tkinter import filedialog
        path = filedialog.asksaveasfilename(defaultextension=".png",
                                            initialfile="karsilastirma_%s.png" % datetime.now().strftime("%Y%m%d_%H%M%S"),
                                            filetypes=[("PNG", "*.png"), ("PDF", "*.pdf")])
        if not path:
            return
        try:
            fig = Figure(figsize=(9, 5.5), dpi=150, facecolor="white"); ax = fig.add_subplot(111)
            for i, s in enumerate(self.compare):
                c = CMP_COLORS[i % len(CMP_COLORS)]; base = self._base_name(s.get("name", "?"))
                ax.errorbar(s.get("Xc", []), s.get("Yc", []),
                            yerr=(s.get("YEc") if s.get("iso", True) else None),
                            xerr=(None if s.get("iso", True) else s.get("XEc")),
                            fmt="o", ms=4, color=c, ecolor=c, capsize=2, label=base[:18])
                if len(s.get("Xc", [])) >= 2:
                    X = np.array(s["Xc"]); m, b = np.polyfit(X, np.array(s["Yc"]), 1)
                    xs = np.linspace(X.min(), X.max(), 50); ax.plot(xs, m * xs + b, color=c, lw=1.0)
            ax.set_title("B Strain Sensor - Comparison", fontsize=13, fontweight="bold")
            ax.set_xlabel("time t [s]"); ax.set_ylabel("dR/R0 [%]")
            ax.grid(True, alpha=0.3); ax.legend(fontsize=8)
            fig.tight_layout(); fig.savefig(path); self.log("Karsilastirma grafigi kaydedildi: %s" % path)
        except Exception as e:
            self.log("Karsilastirma grafik hatasi: %s" % e)

    def _cmp_save_csv(self):
        if not self.compare:
            self.log("Karsilastirilacak olcum yok."); return
        from tkinter import filedialog
        path = filedialog.asksaveasfilename(defaultextension=".csv",
                                            initialfile="karsilastirma_%s.csv" % datetime.now().strftime("%Y%m%d_%H%M%S"),
                                            filetypes=[("CSV", "*.csv")])
        if not path:
            return
        try:
            with open(path, "w", newline="", encoding="utf-8") as f:
                w = csv.writer(f); w.writerow(["# B Strain Sensor - Karsilastirma"])
                w.writerow(["numune", "mod", "R0[ohm]", "maks_dRR[%]", "GF", "tekrar"])
                for s in self.compare:
                    w.writerow([s.get("name", "?"), s.get("mode", "?"),
                                "%.6g" % (s.get("R_fit") or float("nan")),
                                "%.6g" % (s.get("Rs") or float("nan")),
                                ("%.6g" % s["rho"]) if s.get("rho") else "",
                                s.get("n_repeats", "")])
            self.log("Karsilastirma CSV kaydedildi: %s" % path)
        except Exception as e:
            self.log("Karsilastirma CSV hatasi: %s" % e)

    # --------------------------------------------- RAPOR
    def _build_report_tab(self, tab):
        wrap = ctk.CTkFrame(tab, fg_color="transparent"); wrap.pack(fill="both", expand=True, padx=6, pady=6)
        bar = ctk.CTkFrame(wrap, fg_color="transparent"); bar.pack(fill="x")
        ctk.CTkLabel(bar, text="RAPOR", font=("Consolas", 14, "bold"), text_color=ACCENT
                     ).pack(side="left", pady=2)
        ctk.CTkButton(bar, text="Mevcut olcumu sec", command=self._rep_use_current, width=150,
                      fg_color=ACCENT, hover_color="#7c3aed").pack(side="left", padx=6)
        ctk.CTkButton(bar, text="PDF RAPOR OLUSTUR", command=self._make_report, width=180,
                      fg_color=OK_GREEN, hover_color="#349a66", text_color="white",
                      font=("Consolas", 13, "bold")).pack(side="right", padx=4)
        ctk.CTkLabel(wrap, text="Arsiv sekmesinden 'Rapor' ile de bir olcum secebilirsiniz.",
                     font=("Consolas", 10), text_color="#9b93b8", anchor="w").pack(fill="x", pady=(2, 4))
        self.report_box = ctk.CTkTextbox(wrap, font=("Consolas", 12), fg_color="#0f1316",
                                         text_color="#cdc6e6", corner_radius=12, wrap="word")
        self.report_box.pack(fill="both", expand=True, pady=(6, 0)); self.report_box.configure(state="disabled")
        self._refresh_report()

    def _rep_use_current(self):
        if not self.sample or "Xc" not in self.sample:
            self.log("Once bir olcum yapin/yukleyin."); return
        self.report_target = self.sample; self._refresh_report()

    def _refresh_report(self):
        s = self.report_target
        self.report_box.configure(state="normal"); self.report_box.delete("1.0", "end")
        if not s:
            self.report_box.insert("1.0", "Henuz rapor icin bir olcum secilmedi. "
                                    "'Mevcut olcumu sec' deyin ya da Arsiv'den 'Rapor' butonunu kullanin.")
        else:
            gf = s.get("gauge_factor")
            txt = ["Secili olcum:", "  Numune : %s" % s.get("name", "?"),
                   "  R0     : %s ohm" % fmt_val(s.get("R0")),
                   "  maks dR/R0 : %.1f %%" % (s.get("max_drr") or 0.0),
                   "  Gauge factor : %s" % (("%.2f" % gf) if gf is not None else "--"),
                   "  Sure   : %.1f s" % (s.get("duration") or 0.0),
                   "  Nokta  : %s" % s.get("n", "?"), "",
                   "'PDF RAPOR OLUSTUR' ile tek sayfalik rapor uretebilirsiniz",
                   "(kosullar + dR/R0-zaman grafigi + sonuc tablosu)."]
            self.report_box.insert("1.0", chr(10).join(txt))
        self.report_box.configure(state="disabled")

    def _report_figure(self, s):
        name = s.get("name", "Numune")
        fig = Figure(figsize=(8.27, 11.69), dpi=150, facecolor="white")
        try:
            from matplotlib.backends.backend_agg import FigureCanvasAgg
            FigureCanvasAgg(fig)
        except Exception:
            pass
        fig.text(0.5, 0.965, "B STRAIN SENSOR - MEASUREMENT REPORT", ha="center",
                 fontsize=15, fontweight="bold")
        head = chr(10).join(["Sample: %s" % self._base_name(name),
                             "User: %s %s" % (self.user["first"], self.user["last"]),
                             "Date: %s" % datetime.now().strftime("%Y-%m-%d %H:%M"),
                             "Bias: %s V    NPLC: %s    Points: %s" % (s.get("bias"), s.get("nplc", "?"), s.get("n", "?"))])
        fig.text(0.08, 0.90, head, ha="left", va="top", fontsize=10, family="monospace")
        gf = s.get("gauge_factor")
        res = chr(10).join(["RESULTS",
                            "  R0 = %s" % eng(s.get("R0"), "ohm"),
                            "  max dR/R0 = %.1f %%" % (s.get("max_drr") or 0.0),
                            "  Gauge factor = %s" % (("%.2f" % gf) if gf is not None else "--"),
                            "  Duration = %.1f s" % (s.get("duration") or 0.0)])
        fig.text(0.55, 0.90, res, ha="left", va="top", fontsize=10, family="monospace",
                 bbox=dict(boxstyle="round", fc="#efeaff", ec="#6d28d9"))
        ax1 = fig.add_axes([0.10, 0.30, 0.82, 0.50])
        Xc = np.array(s["Xc"]); Yc = np.array(s["Yc"])
        ax1.plot(Xc, Yc, color="#6d28d9", lw=1.8)
        ax1.set_title("dR/R0 vs time", fontsize=12)
        ax1.set_xlabel("time t [s]"); ax1.set_ylabel("dR/R0 [%]")
        ax1.grid(True, alpha=0.3)
        return fig

    def _make_report(self):
        s = self.report_target
        if not s or "Xc" not in s:
            self.log("Once rapor icin bir olcum secin."); return
        from tkinter import filedialog
        name = s.get("name", "Numune")
        path = filedialog.asksaveasfilename(defaultextension=".pdf",
                                            initialfile="%s_rapor_%s.pdf" % (_safe(name), datetime.now().strftime("%Y%m%d_%H%M%S")),
                                            filetypes=[("PDF", "*.pdf")])
        if not path:
            return
        try:
            fig = self._report_figure(s)
            fig.savefig(path); self.log("PDF rapor kaydedildi: %s" % path)
        except Exception as e:
            self.log("Rapor hatasi: %s" % e)

    # ===================================================== ORTAK / OLCUM
    def log(self, msg):
        ts = datetime.now().strftime("%H:%M:%S")
        self.logbox.configure(state="normal"); self.logbox.insert("end", "[%s] %s\n" % (ts, msg))
        self.logbox.see("end"); self.logbox.configure(state="disabled")

    def _demo_toggled(self):
        if self.connected:
            self.demo_var.set(not self.demo_var.get()); self.log("Once baglantiyi kesin."); return
        if self.demo_var.get():
            self.resource_box.configure(values=["DEMO (simulasyon)"], state="disabled")
            self.resource_box.set("DEMO (simulasyon)")
        else:
            self.resource_box.configure(state="normal"); self.resource_box.set("(tara)")
        try:
            if hasattr(self, "ino_port") and not self.ino_connected:
                self._ino_scan()
        except Exception:
            pass

    def _mode_changed(self, val):
        pass

    def _invalidate_background(self, reason=""):
        self.bg = None

    def scan_devices(self):
        if self.demo_var.get():
            self.log("Demo modu acik; tarama gerekmez."); return
        self.log("VISA kaynaklari taraniyor...")
        res = SMU.list_resources()
        if res:
            self.resource_box.configure(values=res); self.resource_box.set(res[0])
            self.log("Bulunan: %s" % ", ".join(res))
        else:
            self.resource_box.configure(values=["(cihaz yok)"]); self.resource_box.set("(cihaz yok)")
            self.log("Cihaz bulunamadi. GPIB acik mi? NI-VISA kurulu mu?")

    def _set_status(self, text, color):
        self.status_pill.configure(text="  %s  " % text, fg_color=color)

    def toggle_connect(self):
        self._disconnect() if self.connected else self._connect()

    def _connect(self):
        try:
            if self.demo_var.get():
                self.smu = SMU(simulate=True, sim_resistance=self._get_float("sim_R", 1000.0))
            else:
                res = self.resource_box.get()
                if res in ("(tara)", "(cihaz yok)", ""):
                    self.log("Once gecerli bir cihaz secin (Cihaz Tara)."); return
                self.smu = SMU(resource=res, simulate=False)
            idn = self.smu.connect(); self.connected = True
            self._set_status("BAGLI", OK_GREEN); self.btn_connect.configure(text="Kes")
            self.safety_ok = False
            self.safety_pill.configure(text=" Guvenlik: bekliyor ", fg_color="#4a2a1a", text_color="#e6a98a")
            self._invalidate_background("")
            self.log("Baglandi: %s" % idn)
            self.log("Devam etmek icin GUVENLIK KONTROLU'nu tamamlayin.")
            self._update_buttons()
        except Exception as e:
            self.log("Baglanti hatasi: %s" % e); self._set_status("HATA", WARN_RED)

    def _disconnect(self):
        if self.worker and self.worker.is_alive():
            self.stop_sweep()
        if self.smu:
            self.smu.close()
        self.smu = None; self.connected = False; self.safety_ok = False
        self._set_status("BAGLI DEGIL", WARN_RED); self.btn_connect.configure(text="Baglan")
        self.safety_pill.configure(text=" Guvenlik: bekliyor ", fg_color="#4a2a1a", text_color="#e6a98a")
        self._invalidate_background(""); self.log("Baglanti kesildi."); self._update_buttons()

    def _update_buttons(self):
        busy = bool(self.worker and self.worker.is_alive())
        self.btn_safety.configure(state="normal" if (self.connected and not busy) else "disabled")
        self.btn_start.configure(state="normal" if (self.connected and self.safety_ok and not busy) else "disabled")
        self.btn_tare.configure(state="normal" if busy else "disabled")
        self.btn_stop.configure(state="normal" if busy else "disabled")
        self.btn_diag.configure(state="normal" if (self.connected and not busy) else "disabled")
        self.btn_connect.configure(state="disabled" if busy else "normal")

    def _pre_measure_check(self, params):
        """Baglama duyarli on-uyari. Tehlike varsa onay ister, iptal edilirse False doner."""
        try:
            warns, danger = self.assistant.context_check(params)
        except Exception:
            warns, danger = [], False
        for w in warns:
            self.log("ON-UYARI: " + w)
        if warns:
            self._chat_add("Batuhan", "Olcum oncesi kontrol:\n- " + "\n- ".join(warns))
        if danger:
            from tkinter import messagebox
            return messagebox.askyesno("Tehlikeli ayar",
                                       "Ayarlarinda tehlikeli bir nokta var:\n\n- "
                                       + "\n- ".join(warns) +
                                       "\n\nYine de devam etmek istiyor musun?")
        return True

    def _get_float(self, key, default=None):
        try:
            txt = self.fields[key].get().strip()
        except Exception:
            return default
        if txt == "":
            return default
        try:
            return float(txt)
        except Exception:
            return default

    def _collect_params(self):
        raw = self.fields["name"].get().strip() or "Numune"
        full = "%s_%s_%s" % (_safe(self.user["first"]), _safe(self.user["last"]), _safe(raw))
        sp = self.fields["strain_pct"].get().strip()
        return {"name": full, "raw_name": raw, "mode": "izleme",
                "bias": self._get_float("bias", 1.0),
                "compliance_i": self._get_float("compliance_i", 1e-2),
                "nplc": self._get_float("nplc", 1.0),
                "interval": self._get_float("interval", 0.05),
                "four_wire": bool(self.fourwire.get()),
                "strain_pct": (float(sp) if sp else None),
                "window_s": self._get_float("window_s", 60.0),
                "thickness": None}

    def start_monitor(self):
        if not (self.connected and self.safety_ok):
            self.log("Once baglanin ve GUVENLIK KONTROLU yapin."); return
        try:
            params = self._collect_params()
        except ValueError:
            self.log("HATA: Sayisal alanlarda gecersiz deger."); return
        self.last_params = params; self.phase = "monitor"; self._reset_curves()
        for k in self.cards:
            self.cards[k].configure(text="--")
        self._style_axes(); self.canvas.draw()
        self.progress.set(0); self.stop_event.clear()
        self.worker = MonitorWorker(self.smu, params, self.q, self.stop_event)
        self.worker.start()
        try:
            self.live_pill.configure(text=" CANLI ", fg_color="#1c4a2e", text_color="#9fe0b8")
        except Exception:
            pass
        self.log("Izleme basladi. Numune gevsekken 'R0 TARA' yapin, sonra cekin.")
        self._update_buttons()

    def _tare(self):
        if len(self.cur_yr) >= 3:
            self.R0 = float(np.median(self.cur_yr[-10:]))
        elif self.cur_yr:
            self.R0 = float(self.cur_yr[-1])
        else:
            self.log("Once BASLAT ile izleme baslasin, sonra R0 tara edin."); return
        self.max_drr = 0.0
        self.cur_yc = [((r - self.R0) / self.R0 * 100.0) for r in self.cur_yr]
        self._card("R0", self.R0)
        self.log("R0 tara edildi: %s" % eng(self.R0, "ohm"))
        self._redraw(live=True)

    def _on_mpoint(self, d):
        t = d["t"]; R = d["R"]
        self.cur_xr.append(t); self.cur_yr.append(R); self.cur_xc.append(t)
        drr = ((R - self.R0) / self.R0 * 100.0) if self.R0 else 0.0
        self.cur_yc.append(drr)
        if self.R0 and drr > self.max_drr:
            self.max_drr = drr
        self._card("R", R, comp=d.get("comp", False))
        if self.R0:
            self._card("drr", drr); self._card("maxdrr", self.max_drr); self._card("R0", self.R0)
        self._redraw(live=True)

    def _on_mdone(self, _ignored=None):
        try:
            self.live_pill.configure(text=" DURUYOR ", fg_color="#3a2a4a", text_color="#c4b5fd")
        except Exception:
            pass
        n = len(self.cur_xc)
        if n < 2:
            self.log("Yeterli veri yok."); self._update_buttons(); return
        R0 = self.R0 if self.R0 else (float(np.median(self.cur_yr[:10])) if self.cur_yr else float("nan"))
        p = self.last_params or {}
        strain = p.get("strain_pct")
        gf = (self.max_drr / strain) if (strain and strain != 0) else None
        z = [0.0] * n
        s = {"name": p.get("name", "Numune"), "raw_name": p.get("raw_name", "Numune"),
             "mode": "izleme", "n": n, "n_repeats": 1, "iso": False, "comp_hits": 0,
             "sweep": list(self.cur_xc), "Xc": list(self.cur_xc), "Yc": list(self.cur_yc),
             "XEc": list(z), "YEc": list(z), "Xr": list(self.cur_xr), "Yr": list(self.cur_yr),
             "XEr": list(z), "YEr": list(z), "reps": [], "Ib": list(z), "Vb": list(z),
             "rep_label": "dR/R0 [%]",
             "R0": R0, "max_drr": self.max_drr, "gauge_factor": gf,
             "duration": (self.cur_xc[-1] if self.cur_xc else 0.0),
             "bias": p.get("bias"), "nplc": p.get("nplc"), "interval": p.get("interval"),
             "strain_pct": strain, "thickness": None,
             "R_fit": R0, "Rs": self.max_drr, "rho": gf, "dR": None, "R_raw": R0}
        s["n_cycles"] = int(getattr(self, "cyc_total", 1) or 1)
        if self.tele_t and len(self.tele_t) >= 2:
            ft = np.array(self.tele_t); ff = np.array(self.tele_force); fp = np.array(self.tele_pos)
            xc = np.array(self.cur_xc)
            s["Force"] = list(np.interp(xc, ft, ff)); s["Pos"] = list(np.interp(xc, ft, fp))
            s["L0"] = self.L0; s["strain_series"] = list(np.array(s["Pos"]) / (self.L0 or 1.0) * 100.0)
            s["max_force"] = float(np.nanmax(ff))
            try:
                _a = self.mfields["area"].get().strip(); s["area_mm2"] = float(_a) if _a else None
            except Exception:
                s["area_mm2"] = None
        self.pull_active = False
        self.sample = s
        self.btn_csv.configure(state="normal"); self.btn_png.configure(state="normal")
        self.log("Izleme bitti. R0=%s, maks dR/R0=%.1f%%%s, sure=%.1fs"
                 % (eng(R0, "ohm"), self.max_drr,
                    (", GF=%.2f" % gf) if gf is not None else "", s["duration"]))
        try:
            self.store.add_measurement(self.user["id"], s); self.log("Olcum profilinize kaydedildi.")
        except Exception:
            pass
        try:
            comment = self.assistant.comment(s); self.log("ASISTAN: " + comment); self._chat_add("Batuhan", comment)
        except Exception:
            pass
        try:
            self._refresh_profile()
        except Exception:
            pass
        self._redraw(); self._update_buttons()

    def start_sample(self):
        self.start_monitor()

    def stop_sweep(self):
        self.stop_event.set(); self.log("Durdurma istegi gonderildi...")
        try:
            if self.ino_connected and self.pull_active:
                self.ino.send("STOP"); self.pull_active = False; self._ino_update_buttons()
        except Exception:
            pass

    def _drain_queue(self):
        try:
            while True:
                kind, data = self.q.get_nowait()
                if kind == "log":
                    self.log(data)
                elif kind == "mpoint":
                    self._on_mpoint(data)
                elif kind == "mdone":
                    self._on_mdone(data)
                elif kind == "point":
                    self._on_point(data)
                elif kind == "done":
                    self._on_done(data)
                elif kind == "error":
                    self.log("CIHAZ HATASI: %s" % data); self._update_buttons()
        except queue.Empty:
            pass
        self.after(60, self._drain_queue)

    def _fmt(self, x):
        return fmt_val(x)

    def _on_bgpoint(self, d):
        self.cur_xb.append(d["x"]); self.cur_yb.append(d["y"])
        self.ax.clear(); self._style_axes(title="BACKGROUND olcumu...")
        self.ax.scatter(self.cur_xb, self.cur_yb, s=22, color=RAW_CLR, marker="x", zorder=3)
        self.canvas.draw_idle(); self.progress.set((d["idx"] + 1) / d["n"])

    def _on_bg_done(self, data):
        self.bg = data
        self.bg_pill.configure(text=" BG: var (%s, %dx%d) " % (data["mode"], len(data["sweep"]), data["n_repeats"]),
                               fg_color="#1c4a2e", text_color="#9fe0b8")
        self._update_buttons(); self.log("Artik NUMUNE olcebilirsiniz (2. dugme).")

    def _on_point(self, d):
        self.cur_xc.append(d["xc"]); self.cur_yc.append(d["yc"])
        self.cur_xce.append(d["xce"]); self.cur_yce.append(d["yce"])
        self.cur_xr.append(d["xr"]); self.cur_yr.append(d["yr"])
        self.cur_xer.append(d["xer"]); self.cur_yer.append(d["yer"])
        self.cur_reps.append(d["reps"]); self.cur_sets.append(d["set"])
        self._card("V", d["yc"]); self._card("I", d["xc"]); self._card("R", d["R"], comp=d["comp"])
        self._redraw(live=True); self.progress.set((d["idx"] + 1) / d["n"])

    def _box_label_ticks(self, ax, sets):
        n = len(sets); pos = list(range(1, n + 1)); step = max(1, n // 10)
        ticks = pos[::step]
        ax.set_xticks(ticks); ax.set_xticklabels([("%.2g" % sets[i - 1]) for i in ticks],
                                                 rotation=90, fontsize=6)

    def _redraw(self, live=False):
        self.ax.clear(); self._style_axes()
        if self.cur_xc and self.cur_yc:
            self.ax.plot(self.cur_xc, self.cur_yc, color=ACCENT, lw=2.0, zorder=4)
        try:
            win = float(self.fields["window_s"].get()) if hasattr(self, "fields") else 60.0
        except Exception:
            win = 60.0
        if live and self.cur_xc:
            tmax = self.cur_xc[-1]
            self.ax.set_xlim(max(0, tmax - win), max(win, tmax + 0.5))
        self.canvas.draw_idle()

    def _on_done(self, s):
        self.sample = s; self._redraw(); self._update_buttons()

    def save_csv(self):
        if not self.sample or "Xc" not in self.sample:
            self.log("Kaydedilecek veri yok."); return
        from tkinter import filedialog
        s = self.sample; name = s.get("name", "Numune")
        path = filedialog.asksaveasfilename(defaultextension=".csv",
                                            initialfile="%s_%s.csv" % (_safe(name), datetime.now().strftime("%Y%m%d_%H%M%S")),
                                            filetypes=[("CSV", "*.csv")])
        if not path:
            return
        try:
            with open(path, "w", newline="", encoding="utf-8") as f:
                w = csv.writer(f); w.writerow(["# B Strain Sensor"]); w.writerow(["# numune", name])
                w.writerow(["# kullanici", "%s %s" % (self.user["first"], self.user["last"])])
                w.writerow(["# tarih", datetime.now().isoformat()])
                w.writerow(["# bias[V]", s.get("bias"), "nplc", s.get("nplc"), "ornek_araligi[s]", s.get("interval")])
                gf = s.get("gauge_factor")
                w.writerow(["# R0[ohm]", "%.6g" % (s.get("R0") or float("nan")),
                            "maks_dR/R0[%]", "%.4g" % (s.get("max_drr") or float("nan")),
                            "gauge_factor", ("%.4g" % gf) if gf is not None else ""])
                has_f = bool(s.get("Force"))
                hdr = ["index", "zaman[s]", "R[ohm]", "dR/R0[%]"]
                if has_f:
                    hdr += ["konum[mm]", "gerinim[%]", "kuvvet[N]"]
                w.writerow(hdr)
                for i in range(s["n"]):
                    rowv = [i, "%.4f" % s["Xr"][i], "%.6g" % s["Yr"][i], "%.4f" % s["Yc"][i]]
                    if has_f:
                        rowv += ["%.4f" % s["Pos"][i], "%.4f" % s["strain_series"][i], "%.5f" % s["Force"][i]]
                    w.writerow(rowv)
            self.log("CSV kaydedildi: %s" % path)
        except Exception as e:
            self.log("CSV kayit hatasi: %s" % e)

    def _rep_label_en(self, s):
        iso = s.get("iso", s.get("mode") == "isource")
        return "dR/R0 [%]" if iso else "time t [s]"

    def _iv_export_figure(self, s, name):
        fig = Figure(figsize=(10, 4.6), dpi=150, facecolor="white")
        try:
            from matplotlib.backends.backend_agg import FigureCanvasAgg
            FigureCanvasAgg(fig)
        except Exception:
            pass
        fig.suptitle("B Strain Sensor  -  %s" % self._base_name(name), fontsize=13, fontweight="bold")
        Xc = np.array(s["Xc"]); Yc = np.array(s["Yc"])
        a1 = fig.add_subplot(111)
        a1.plot(Xc, Yc, color="#6d28d9", lw=1.8)
        gf = s.get("gauge_factor")
        sub = "R0=%s   max dR/R0=%.1f%%%s" % (eng(s.get("R0"), "ohm"), (s.get("max_drr") or 0.0),
              ("   GF=%.2f" % gf) if gf is not None else "")
        a1.set_title(sub, fontsize=10)
        a1.set_xlabel("time t [s]"); a1.set_ylabel("dR/R0 [%]")
        a1.grid(True, alpha=0.3)
        fig.tight_layout(rect=[0, 0, 1, 0.95])
        return fig

    def save_graph(self):
        if not self.sample or "Xc" not in self.sample:
            self.log("Kaydedilecek grafik yok."); return
        from tkinter import filedialog
        s = self.sample; name = s.get("name", "Numune")
        path = filedialog.asksaveasfilename(defaultextension=".png",
                                            initialfile="%s_dRR_%s.png" % (_safe(name), datetime.now().strftime("%Y%m%d_%H%M%S")),
                                            filetypes=[("PNG", "*.png"), ("PDF", "*.pdf")])
        if not path:
            return
        try:
            fig = self._iv_export_figure(s, name)
            fig.savefig(path); self.log("Grafik kaydedildi: %s" % path)
        except Exception as e:
            self.log("Grafik kayit hatasi: %s" % e)

    def save_box(self):
        if not self.sample or not self.sample.get("reps"):
            self.log("Kaydedilecek kutu grafigi yok."); return
        from tkinter import filedialog
        s = self.sample; name = s.get("name", "Numune")
        path = filedialog.asksaveasfilename(defaultextension=".png",
                                            initialfile="%s_kutu_%s.png" % (_safe(name), datetime.now().strftime("%Y%m%d_%H%M%S")),
                                            filetypes=[("PNG", "*.png"), ("PDF", "*.pdf")])
        if not path:
            return
        try:
            reps = [r for r in s["reps"] if len(r) > 0]; sets = s["sweep"][:len(reps)]
            fig = Figure(figsize=(11, 5.0), dpi=150, facecolor="white")
            fig.suptitle("B Strain Sensor  -  %s  -  Box/Whisker Plot (repeats=%d)" % (self._base_name(name), s["n_repeats"]),
                         fontsize=13, fontweight="bold")
            ax = fig.add_subplot(111)
            ax.boxplot(reps, positions=list(range(1, len(reps) + 1)), widths=0.55, patch_artist=True,
                       boxprops=dict(facecolor="#cfe0e4", color="#5b21b6"),
                       medianprops=dict(color="#C8443A", linewidth=1.6),
                       whiskerprops=dict(color="#5b21b6"), capprops=dict(color="#5b21b6"))
            ax.plot(range(1, len(reps) + 1), [float(np.mean(r)) for r in reps], color="#5b21b6",
                    lw=1.2, marker="o", ms=4, label="Mean")
            step = max(1, len(sets) // 12); ticks = list(range(1, len(reps) + 1))[::step]
            ax.set_xticks(ticks); ax.set_xticklabels(["%.2g" % sets[i - 1] for i in ticks], rotation=90, fontsize=7)
            ax.set_xlabel("Measurement point (set value)"); ax.set_ylabel(self._rep_label_en(s))
            ax.grid(True, alpha=0.3); ax.legend(fontsize=9)
            fig.tight_layout(rect=[0, 0, 1, 0.95]); fig.savefig(path); self.log("Kutu grafigi kaydedildi: %s" % path)
        except Exception as e:
            self.log("Kutu grafigi hatasi: %s" % e)

    def _mlog(self, msg):
        ts = datetime.now().strftime("%H:%M:%S")
        try:
            self.mlog.insert("end", "[%s] %s" % (ts, msg) + chr(10)); self.mlog.see("end")
        except Exception:
            pass

